resource "aws_route53_zone" "private" {
  name = "private"
}

resource "aws_route53_zone" "public" {
  name = "public"
}

resource "aws_db_subnet_group" "main" {
  name       = "main"
  subnet_ids = var.subnet_ids
}

resource "aws_db_instance" "internal" {
  identifier           = "internal"
  db_subnet_group_name = aws_db_subnet_group.main.name
  allocated_storage    = 20
  engine               = "mysql"
  instance_class       = "db.t3.micro"
  username             = "admin"
  password             = "password"
  publicly_accessible  = false
}

resource "aws_db_instance" "public" {
  identifier           = "public"
  db_subnet_group_name = aws_db_subnet_group.main.name
  allocated_storage    = 20
  engine               = "mysql"
  instance_class       = "db.t3.micro"
  username             = "admin"
  password             = "password"
  publicly_accessible  = true
}

resource "aws_route53_record" "internal" {
  zone_id = aws_route53_zone.private.zone_id
  name    = "internal.private"
  type    = "CNAME"
  records = [aws_db_instance.internal.endpoint]
  ttl     = 300
}

resource "aws_route53_record" "public" {
  zone_id = aws_route53_zone.public.zone_id
  name    = "public.public"
  type    = "CNAME"
  records = [aws_db_instance.public.endpoint]
  ttl     = 300
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "Main VPC"
  }
}

resource "aws_vpc_endpoint" "route53_resolvers" {
  vpc_id       = aws_vpc.main.id
  service_name = "com.amazonaws.${var.region}.route53-resolver"
  subnet_ids   = var.subnet_ids
}

resource "aws_route53_resolver_rule" "private_dns" {
  domain_name = "private"
  rule_type   = "FORWARD"
  name        = "forward-private-dns"

  resolver_endpoint_id = aws_vpc_endpoint.route53_resolvers.id

  target_ip {
    ip = aws_db_instance.internal.endpoint
  }

  lifecycle {
    ignore_changes = [target_ip] # endpoint may change during DB instance updates
  }
}

resource "aws_route53_resolver_rule_association" "private_dns_assoc" {
  resolver_rule_id = aws_route53_resolver_rule.private_dns.id
  vpc_id           = aws_vpc.main.id
}
```

