terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_iam_role" "eb_ec2_role2" {
  name = "elastic_beanstalk_ec2_role2"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "ec2.amazonaws.com"
        },
      },
    ]
  })
}

# Attach the AWS managed policy for Elastic Beanstalk to the role
resource "aws_iam_role_policy_attachment" "eb_managed_policy" {
  role       = aws_iam_role.eb_ec2_role2.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}


# Create an instance profile tied to the role
resource "aws_iam_instance_profile" "eb_ec2_profile1" {
  name = "elastic_beanstalk_ec2_profile2"
  role = aws_iam_role.eb_ec2_role2.name
}

resource "aws_db_instance" "myapp_db" {
  allocated_storage    = 20
  storage_type         = "gp2"
  engine               = "mysql"
  engine_version       = "5.7"
  instance_class       = "db.t3.micro"
  username             = "dbadmin"
  password             = "mypassword"
  parameter_group_name = "default.mysql5.7"
  skip_final_snapshot  = true
}

resource "aws_elastic_beanstalk_application" "myapp" {
  name        = "my-application"
  description = "my application"
}

resource "aws_elastic_beanstalk_environment" "myenv" {
  name                = "my-environment"
  application         = aws_elastic_beanstalk_application.myapp.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_HOST"
    value     = aws_db_instance.myapp_db.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_USERNAME"
    value     = aws_db_instance.myapp_db.username
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_PASSWORD"
    value     = aws_db_instance.myapp_db.password
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile1.name
  }
}

resource "aws_route53_zone" "main" {
  name = "example56.com"
}

resource "aws_route53_record" "www" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "app.example56.com"
  type    = "CNAME"
  ttl     = 60
  records = [aws_elastic_beanstalk_environment.myenv.cname]
}

response:
```hcl
provider "aws" {
  region = "us-east-1"
}

resource "aws_elastic_beanstalk_application" "app" {
  name        = "myapp"
  description = "My Elastic Beanstalk application"
}

resource "aws_elastic_beanstalk_environment" "env" {
  name                = "myenv"
  application         = aws_elastic_beanstalk_application.app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.3.6"

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = "eb_ec2_profile1"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentName"
    value     = "myenv"
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBDeletionPolicy"
    value     = "Snapshot"
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBInstanceClass"
    value     = "db.t3.micro"
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBEngine"
    value     = "mysql"
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "DBName"
    value     = "myapp_db"
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "MultiAZ"
    value     = "false"
  }

  setting {
    namespace = "aws:rds:dbinstance"
    name      = "AllocatedStorage"
    value     = "20"
  }
}

resource "aws_route53_zone" "domain" {
  name = "myapp.com"
}

resource "aws_route53_record" "www" {
  zone_id = aws_route53_zone.domain.zone_id
  name    = "myapp.com"
  type    = "A"

  alias {
    name                   = aws_elastic_beanstalk_environment.env.cname
    zone_id                = aws_elastic_beanstalk_environment.env.cname_zone_id
    evaluate_target_health = false
  }
}

resource "aws_route53_record" "www_wildcard" {
  zone_id = aws_route53_zone.domain.zone_id
  name    = "*.myapp.com"
  type    = "CNAME"
  ttl     = 300
  records = [aws_elastic_beanstalk_environment.env.cname]
}
```

