          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
      },
      {
        Effect = "Allow"
        Resource = "*"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:GetBucketAcl",
          "s3:GetBucketLocation"
        ]
      }
    ]
  })
}

resource "aws_codebuild_project" "example" {
  name         = "example-codebuild-project"
  description  = "An example CodeBuild project using GitHub source"
  service_role = aws_iam_role.codebuild_role.arn

  source {
    type      = "GITHUB"
    location  = "https://github.com/example-user/example-repo.git"
    git_clone_depth = 1

    buildspec = jsonencode({
      version = "0.2"
      phases = {
        install = {
          commands = [
            "echo Installing dependencies...",
            "npm install"
          ]
        }
        build = {
          commands = [
            "echo Build started on `date`",
            "npm run build"
          ]
        }
      }
      artifacts = {
        files = [
          "**/*"
        ]
      }
    })
  }

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    type                = "LINUX_CONTAINER"
    image               = "aws/codebuild/standard:5.0"
    compute_type        = "BUILD_GENERAL1_SMALL"
    privileged_mode     = false
  }

  logs_config {
    cloudwatch_logs {
      group_name = "/aws/codebuild/${aws_codebuild_project.example.name}"
      stream_name = "main"
    }

    s3_logs {
      status = "DISABLED"
    }
  }
}

