resource "aws_codebuild_project" "sample_project" {
  name         = "sample-codebuild-project"
  description  = "Sample project with secondary artifacts"
  service_role = aws_iam_role.codebuild_role.arn

  source {
    type      = "S3"
    location  = "${aws_s3_bucket.source_bucket.bucket}/source-code.zip"
    buildspec = "buildspec.yml"
  }

  artifacts {
    type = "S3"
    location = aws_s3_bucket.artifact_bucket.bucket
    name = "primary-output"
  }

  secondary_artifacts {
    type = "S3"
    location = aws_s3_bucket.secondary_artifact_bucket.bucket
    name = "secondary-output-1"
    packaging = "ZIP"
  }

  secondary_artifacts {
    type = "S3"
    location = aws_s3_bucket.secondary_artifact_bucket.bucket
    name = "secondary-output-2"
    packaging = "NONE"
