      group_name = "/aws/codebuild/${aws_codebuild_project.sample_project.name}"
      stream_name = "main"
    }

    s3_logs {
      status   = "ENABLED"
      location = "${aws_s3_bucket.artifact_bucket.bucket}/logs"
    }
  }

  tags = {
    Project = "Sample"
    Owner   = "DevOps"
  }
}

