resource "aws_lex_intent" "order_flowers_intent" {
  name = "OrderFlowerIntent"

  slot {
    name                 = "FlowerType"
    slot_type            = "AMAZON.LITERAL"
    slot_type_version    = "1"
    value_elicitation_prompt {
      message {
        content      = "What type of flowers would you like to order?"
        content_type = "PlainText"
      }
      max_attempts = 2
    }
    priority = 1
    sample_utterances = [
      "I want to order {FlowerType}",
      "Buy some {FlowerType}"
    ]
    slot_constraint = "Required"
  }

  slot {
    name                 = "PickupTime"
    slot_type            = "AMAZON.TIME"
    slot_type_version    = "1"
    value_elicitation_prompt {
      message {
        content      = "When would you like to pick up the flowers?"
        content_type = "PlainText"
      }
      max_attempts = 2
    }
    priority = 2
    sample_utterances = [
      "Pickup at {PickupTime}",
      "I will pick up at {PickupTime}"
    ]
    slot_constraint = "Required"
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }

  sample_utterances = [
    "I want to order flowers",
    "Order some flowers"
  ]
}

resource "aws_lex_intent" "book_hotel_intent" {
  name = "BookHotelIntent"

  slot {
    name                 = "CheckInDate"
    slot_type            = "AMAZON.DATE"
    slot_type_version    = "1"
    value_elicitation_prompt {
      message {
        content      = "What is your check-in date?"
        content_type = "PlainText"
      }
      max_attempts = 2
    }
    priority = 1
    sample_utterances = [
      "Check in on {CheckInDate}",
      "Arriving {CheckInDate}"
    ]
    slot_constraint = "Required"
  }

  slot {
    name                 = "CheckOutDate"
    slot_type            = "AMAZON.DATE"
    slot_type_version    = "1"
    value_elicitation_prompt {
      message {
        content      = "What is your check-out date?"
        content_type = "PlainText"
      }
      max_attempts = 2
    }
    priority = 2
    sample_utterances = [
      "Check out on {CheckOutDate}",
      "Leaving {CheckOutDate}"
    ]
    slot_constraint = "Required"
  }

  slot {
    name                 = "RoomType"
    slot_type            = "AMAZON.LITERAL"
    slot_type_version    = "1"
    value_elicitation_prompt {
      message {
        content      = "What type of room would you like?"
        content_type = "PlainText"
      }
      max_attempts = 2
    }
    priority = 3
    sample_utterances = [
      "Book a {RoomType} room",
      "I need a {RoomType}"
    ]
    slot_constraint = "Required"
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }

  sample_utterances = [
    "I want to book a hotel",
    "Book a room for me"
  ]
}

# Ensure intents are created before the bot
depends_on = [
  aws_lex_intent.order_flowers_intent,
  aws_lex_intent.book_hotel_intent
]

