resource "aws_lex_intent" "order_pizza_intent" {
  name        = "OrderPizza"
  description = "Orders a pizza based on customer preferences"

  slot {
    name                 = "PizzaSize"
    slot_type            = "AMAZON.Number"
    slot_type_name       = "AMAZON.Number"
    value_elicitation_prompt {
      message {
        content      = "What size pizza would you like? For example, 10, 12, or 14 inches."
        content_type = "PlainText"
      }
      max_attempts = 2
    }
    priority              = 1
    sample_utterances     = ["small", "medium", "large", "10 inch", "12 inch", "14 inch"]
    slot_constraint       = "Required"
  }

  slot {
    name                 = "Toppings"
    slot_type_name       = "AMAZON.Food"
    value_elicitation_prompt {
      message {
        content      = "What toppings would you like on your pizza?"
        content_type = "PlainText"
      }
      max_attempts = 3
    }
    priority              = 2
    sample_utterances     = ["pepperoni", "mushrooms", "extra cheese", "olives"]
    slot_constraint       = "Optional"
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }

  sample_utterances = [
    "I want to order a pizza",
    "Can I get a pizza?",
    "Order a pizza with pepperoni",
    "I'd like to place a pizza order"
  ]

  conclusion_statement {
    message {
      content      = "Great! I've ordered your {PizzaSize}-inch pizza with {Toppings}. Your order will be ready in 30 minutes. Thank you!"
      content_type = "PlainText"
    }
  }
}

