      content_type = "PlainText"
      group_number = 1
    }
    message {
      content      = "The operation has been aborted."
      content_type = "SSML"
      group_number = 2
    }
    response_card = "{"version":1,"contentType":"application/vnd.amazonaws.card.action","genericAttachments":[{"title":"Need help?","subTitle":"Contact support.","buttons":[{"text":"Call Support","value":"CALL_SUPPORT"}]}]}"
  }
  intent {
    intent_name    = "BookHotel"
    intent_version = "$LATEST"
  }
  intent {
    intent_name    = "BookCar"
    intent_version = "$LATEST"
  }
  create_version = true
  process_behavior = "SAVE"
  voice_id         = "Joanna"
  checksum           = ""
  detect_sentiment   = true
}

resource "aws_iam_role" "lex_bot_role" {
  name = "lex-bot-trip-reservation-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "lex_bot_policy" {
  name = "lex-bot-trip-reservation-policy"
  role = aws_iam_role.lex_bot_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "cloudwatch:PutMetricData",
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents",
          "polly:SynthesizeSpeech",
          "s3:GetObject"
        ]
        Effect   = "Allow"
        Resource = "*"
      }
    ]
  })
}

