```hcl
```hcl
# Define the AWS provider
provider "aws" {
  region = "us-east-1"
}

# Create an Amazon Lex bot for pizza ordering
resource "aws_lex_bot" "pizza_ordering_bot" {
  name                = "PizzaOrderingForKids"
  description         = "A fun and friendly bot to help children place pizza orders"
  child_directed      = true
  abort_statement {
    message {
      content          = "Sorry, I couldn't help with your order. Goodbye!"
      content_type     = "PlainText"
    }
  }
  clarification_prompt {
    message {
      content          = "I didn't understand. Would you like to order a pizza?"
      content_type     = "PlainText"
    }
    max_attempts       = 2
  }
  intent {
    intent_name       = "OrderPizza"
    intent_version    = "$LATEST"
  }
  voice_id            = "Joanna"
  process_behavior    = "BUILD"
}

# Create the OrderPizza intent required by the bot
resource "aws_lex_intent" "order_pizza_intent" {
  name = "OrderPizza"

  # Sample utterances for children
  sample_utterances = [
    "I want pizza",
    "Can I have pizza?",
    "I'm hungry",
    "Order a pepperoni pizza",
    "Get me cheese pizza",
    "I want a big pizza"
  ]

  # Prompt for pizza type
  slot {
    slot_type           = "AMAZON.PizzaType"
    name                = "PizzaType"
    description         = "Type of pizza: cheese, pepperoni, etc."
    slot_constraint     = "Required"
    priority            = 1
    value_elicitation_prompt {
      message {
        content      = "What kind of pizza would you like?"
        content_type = "PlainText"
      }
      max_attempts   = 2
    }
  }

  # Prompt for pizza size
  slot {
    slot_type           = "AMAZON.PizzaSize"
    name                = "PizzaSize"
    description         = "Size of pizza: small, medium, large"
    slot_constraint     = "Required"
    priority            = 2
    value_elicitation_prompt {
      message {
        content      = "What size pizza would you like?"
        content_type = "PlainText"
      }
      max_attempts   = 2
    }
  }

  # Confirmation prompt
  confirmation_prompt {
    message {
      content        = "You want a {PizzaSize} {PizzaType} pizza. Is that right?"
      content_type   = "PlainText"
    }
    max_attempts     = 2
  }

  # Confirmation statement after order
  confirmation_statement {
    message {
      content        = "Great! Your {PizzaSize} {PizzaType} pizza is being prepared. Yum!"
      content_type   = "PlainText"
    }
  }

  # Rejection statement
  rejection_statement {
    message {
      content        = "Okay, no pizza this time. Maybe next time!"
      content_type   = "PlainText"
    }
  }
}
```
