resource "aws_lex_intent" "order_pizza_intent" {
  name               = "OrderPizza"
  description        = "Intent to order a pizza"
  fulfillment_activity {
    type = "CodeHook"
    code_hook {
      uri = aws_lambda_function.pizza_order_handler.arn
      message_version = "1.0"
    }
  }

  slot {
    slot_type           = "AMAZON.Number"
    slot_type_name      = "AMAZON.Number"
    name                = "PizzaCount"
    description         = "Number of pizzas to order"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "How many pizzas would you like to order?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    slot_type           = "AMAZON.Food"
    slot_type_name      = "AMAZON.Food"
    name                = "PizzaType"
    description         = "Type of pizza to order"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What type of pizza would you like?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    slot_type           = "AMAZON.Time"
    slot_type_name      = "AMAZON.Time"
    name                = "DeliveryTime"
    description         = "Preferred delivery time"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "When would you like your pizza delivered?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2
    message {
      content      = "You want {PizzaCount} {PizzaType} pizza(s) delivered at {DeliveryTime}. Is that correct?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Order canceled."
      content_type = "PlainText"
    }
  }

