    intent_name    = "OrderPizza"
    intent_version = "$LATEST"
  }

  clarification_prompt {
    max_attempts = 2
    message {
      content      = "I didn't understand. Can you please repeat your order?"
      content_type = "PlainText"
    }
  }

  voice_id = "Salli"
}

resource "aws_lex_intent" "order_pizza_intent" {
  name               = "OrderPizza"
  description        = "Intent to order a pizza"
  fulfillment_activity {
    type = "CodeHook"
    code_hook {
      uri = aws_lambda_function.pizza_order_handler.arn
      message_version = "1.0"
    }
  }

  slot {
    slot_type           = "AMAZON.Number"
    slot_type_name      = "AMAZON.Number"
    name                = "PizzaCount"
    description         = "Number of pizzas to order"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "How many pizzas would you like to order?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    slot_type           = "AMAZON.Food"
    slot_type_name      = "AMAZON.Food"
    name                = "PizzaType"
    description         = "Type of pizza to order"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "What type of pizza would you like?"
        content_type = "PlainText"
      }
    }
  }

  slot {
    slot_type           = "AMAZON.Time"
    slot_type_name      = "AMAZON.Time"
    name                = "DeliveryTime"
    description         = "Preferred delivery time"
    value_elicitation_prompt {
      max_attempts = 2
      message {
        content      = "When would you like your pizza delivered?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2
    message {
      content      = "You want {PizzaCount} {PizzaType} pizza(s) delivered at {DeliveryTime}. Is that correct?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
      content      = "Order canceled."
      content_type = "PlainText"
    }
  }

  sample_utterances = [
    "I want to order a pizza",
    "I would like to buy a pizza",
    "Order a pizza",
    "Get me a pizza"
  ]
}

resource "aws_lambda_function" "pizza_order_handler" {
  filename      = "lambda_function_payload.zip"
  function_name = "PizzaOrderHandler"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  runtime       = "nodejs18.x"

  source_code_hash = filebase64sha256("lambda_function_payload.zip")

  environment {
    variables = {
      LOG_LEVEL = "INFO"
    }
  }
}

resource "aws_iam_role" "lex_bot_role" {
  name = "LexBotRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lex.amazonaws.com"
        }
      }
    ]
  })
}

