resource "aws_kinesis_analytics_application" "kinesis_analytics_app" {
  name = "example-kinesis-analytics-app"

  input {
    name_prefix = "input-stream"

    kinesis_stream {
      resource_arn = aws_kinesis_stream.input_stream.arn
      role_arn     = aws_iam_role.kinesis_role.arn
    }

    // Define a sample input schema
    input_schema {
      record_format_type = "JSON"

      mapping_parameters {
        json {
          record_row_path = "$"
        }
      }

      record_column {
        name = "column1"
        sql_type = "VARCHAR(16)"
        mapping = "$.column1"
      }
    }
  }
}

