```hcl
```hcl
resource "aws_kinesis_firehose_delivery_stream" "firehose_to_elasticsearch" {
  name        = "firehose-to-es"
  destination = "elasticsearch"

  elasticsearch_configuration {
    domain_arn = aws_elasticsearch_domain.example.arn
    role_arn   = aws_iam_role.firehose_role.arn
    index_name = "firehose-logs"
    type_name  = "record"
    index_rotation = "OneHour"
    buffering_interval = 300
    buffering_size     = 5
    retry_duration     = 300

    vpc_config {
      subnet_ids         = aws_subnet.example[*].id
      security_group_ids = [aws_security_group.firehose_sg.id]
      vpc_id             = aws_vpc.example.id
    }
  }
}

resource "aws_elasticsearch_domain" "example" {
  domain_name = "firehose-es-domain"
  elasticsearch_version = "7.10"

  cluster_config {
    instance_type = "m5.large.elasticsearch"
    instance_count = 2
  }

  vpc_options {
    subnet_ids         = aws_subnet.example[*].id
    security_group_ids = [aws_security_group.es_sg.id]
  }

  advanced_security_options {
    enabled                        = true
    internal_user_database_enabled = true
  }

  log_publishing_options {
    log_type = "INDEX_SLOW_LOGS"
    enabled  = true
    cloudwatch_log_group_arn = aws_cloudwatch_log_group.es_log_group.arn
  }

  depends_on = [
    aws_iam_service_linked_role.es-linked-role
  ]
}

resource "aws_iam_role" "firehose_role" {
  name = "firehose_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_delivery_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "es:DescribeElasticsearchDomain",
          "es:DescribeElasticsearchDomains",
          "es:DescribeElasticsearchDomainConfig",
          "es:ESHttpPut",
          "es:ESHttpPost"
        ]
        Resource = aws_elasticsearch_domain.example.arn
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:DescribeVpcs",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeNetworkInterfaces",
          "ec2:CreateNetworkInterface",
          "ec2:CreateNetworkInterfacePermission",
          "ec2:DeleteNetworkInterface"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "logs:PutLogEvents"
        ]
        Resource = aws_cloudwatch_log_group.firehose_log_group.arn
      }
    ]
  })
}

resource "aws_cloudwatch_log_group" "firehose_log_group" {
  name = "/aws/firehose/firehose-to-es"
}

resource "aws_cloudwatch_log_group" "es_log_group" {
  name = "es-slow-logs"
}

resource "aws_vpc" "example" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "firehose-vpc"
  }
}

resource "aws_subnet" "example" {
  count             = 2
  cidr_block        = cidrsubnet(aws_vpc.example.cidr_block, 8, count.index)
  vpc_id            = aws_vpc.example.id
  availability_zone = element(data.aws_availability_zones.available.names, count.index)

  tags = {
    Name = "firehose-subnet-${count.index}"
  }
}

resource "aws_security_group" "firehose_sg" {
  name        = "firehose-sg"
  description = "Allow firehose to access Elasticsearch"
  vpc_id      = aws_vpc.example.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_security_group" "es_sg" {
  name        = "es-sg"
  description = "Allow access to Elasticsearch"
  vpc_id      = aws_vpc.example.id

  ingress {
    from_port       = 443
    to_port         = 443
    protocol        = "tcp"
    security_groups = [aws_security_group.firehose_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_iam_service_linked_role" "es-linked-role" {
  aws_service_name = "es.amazonaws.com"
}
