# IAM Role for Firehose to access S3 and write logs
resource "aws_iam_role" "firehose_role" {
  name = "firehose-s3-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# IAM Policy for Firehose S3 and CloudWatch access
resource "aws_iam_policy" "firehose_policy" {
  name = "firehose-s3-cloudwatch-policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.s3_bucket.arn,
          "${aws_s3_bucket.s3_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:log-group:/aws/kinesis/firehose/http-endpoint:log-stream:*"
      }
    ]
  })
}

resource "aws_iam_policy_attachment" "firehose_s3_policy_attach" {
  policy_arn = aws_iam_policy.firehose_policy.arn
  roles      = [aws_iam_role.firehose_role.name]
}

# S3 Bucket for buffering data
resource "aws_s3_bucket" "s3_bucket" {
  bucket = "firehose-http-endpoint-buffer"
}

# Enable versioning on S3 bucket
resource "aws_s3_bucket_versioning" "versioning" {
  bucket = aws_s3_bucket.s3_bucket.id
  versioning_configuration {
    status = "Enabled"
  }
}

