resource "aws_kinesis_firehose_delivery_stream" "firehose_to_http_endpoint" {
  name        = "firehose-http-endpoint-stream"
  destination = "http_endpoint"

  http_endpoint_configuration {
    url      = "https://your-new-relic-endpoint.com"
    name     = "NewRelicEndpoint"
    access_key = "your-access-key" # Optional if required by the endpoint

    s3_configuration {
      role_arn   = aws_iam_role.firehose_role.arn
      bucket_arn = aws_s3_bucket.s3_bucket.arn

      # Optional: Add buffer and compression settings
      buffer_size            = 5
      buffer_interval        = 300
      compression_format     = "GZIP"
      error_output_prefix    = "errors/year=!{timestamp:yyyy}/month=!{timestamp:MM}/day=!{timestamp:dd}/hour=!{timestamp:HH}/"
      cloudwatch_logging_options {
        enabled         = true
        log_group_name  = "/aws/kinesis/firehose/http-endpoint"
        log_stream_name = "firehose-stream"
      }
    }

    # Optional: Define custom headers if required by the destination
    # common_attributes {
    #   name  = "custom_header_name"
    #   value = "custom_header_value"
    # }

    # Specify the data format conversion (optional)
    # data_format_conversion_configuration {
    #   enabled = false
    # }

    # Define request and retry configuration
    request_configuration {
      content_encoding = "GZIP"

      common_attributes {
        name  = "region"
        value = "us-west-2"
      }
    }

    retry_options {
      duration = 300
    }
  }

  tags = {
    Environment = "dev"
    Project     = "monitoring"
  }
}

