resource "aws_kinesis_firehose_delivery_stream" "opensearch_stream" {
  name        = "firehose-to-opensearch"
  destination = "opensearch"

  destination_configuration {
    opensearch_configuration {
      role_arn        = aws_iam_role.firehose_role.arn
      domain_arn      = aws_opensearch_domain.example.arn
      index_name      = "firehose-logs"
      type_name       = "log"
      index_rotation  = "NoRotation"

      vpc_config {
        subnet_ids         = [aws_subnet.opensearch_subnet_az1.id, aws_subnet.opensearch_subnet_az2.id]
        security_group_ids = [aws_security_group.opensearch_sg.id]
        role_arn           = aws_iam_role.firehose_role.arn
      }

      buffer_size      = 5
      buffer_interval  = 300
      retry_duration   = 300

      s3_configuration {
        role_arn   = aws_iam_role.firehose_role.arn
        bucket_arn = aws_s3_bucket.firehose_bucket.arn
        buffer_size = 5
        buffer_interval = 300
      }
    }
  }
}

resource "aws_s3_bucket" "firehose_bucket" {
  bucket = "firehose-opensearch-buffer-bucket"
  force_destroy = true
}
