resource "aws_kinesis_firehose_delivery_stream" "s3_delivery_stream" {
  name        = "extended-s3-delivery-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.bucket.arn

    # Optional but recommended settings
    buffer_size            = 10
    buffer_interval        = 300
    compression_format     = "GZIP"
    error_output_prefix    = "errors/year=!{timestamp:yyyy}/month=!{timestamp:MM}/day=!{timestamp:dd}/hour=!{timestamp:HH}/"
    prefix                 = "data/year=!{timestamp:yyyy}/month=!{timestamp:MM}/day=!{timestamp:dd}/hour=!{timestamp:HH}/"
    dynamic_partitioning {
      enabled                      = true
      default_partition_path       = "default/"
      non_key_attribute_paths      = []
      prefix                       = "partitioned/"
    }

    processing_configuration {
      enabled = true

      processors {
        type = "Lambda"

        parameters {
          parameter_name  = "LambdaArn"
          parameter_value = "arn:aws:lambda:us-west-2:123456789012:function:ProcessFirehose"
        }
        parameters {
          parameter_name  = "BufferSizeInMBs"
          parameter_value = "3"
        }
        parameters {
          parameter_name  = "BufferIntervalInSeconds"
          parameter_value = "60"
        }
      }
    }
  }
}

