        "documents/",
      ]
    }
  }

  description         = "Example Kendra data source with proxy settings"
  language_code       = "en"
  role_arn            = aws_iam_role.example.arn
  schedule            = "cron(0 10 * * ? *)"

  custom_document_enrichment_configuration {
    inline_configurations {
      condition {
        condition_document_attribute_key = "_source_uri"
        operator                         = "BEGINS_WITH"
        condition_on_value {
          string_value = "https://example.com"
        }
      }

      target {
        target_document_attribute_key = "category"
        target_document_attribute_value {
          string_value = "example-site"
        }
      }

      document_content_deletion = false
    }

    pre_extraction_hook_configuration {
      lambda_arn = aws_lambda_function.pre_extraction.arn
      s3_bucket  = aws_s3_bucket.code.bucket
      s3_key     = "pre-extraction.zip"

      invocation_condition {
        condition_document_attribute_key = "_source_uri"
        operator                         = "BEGINS_WITH"
        condition_on_value {
          string_value = "https://internal.example.com"
        }
      }
    }

    post_extraction_hook_configuration {
      lambda_arn = aws_lambda_function.post_extraction.arn
      s3_bucket  = aws_s3_bucket.code.bucket
      s3_key     = "post-extraction.zip"
    }
  }

  tags = {
    Name = "ExampleKendraDataSource"
  }

  // Proxy configuration is included via VPC configuration
  vpc_configuration {
    subnet_ids = [
      aws_subnet.example1.id,
      aws_subnet.example2.id
    ]

    security_group_ids = [
      aws_security_group.example.id
    ]

    // Proxy settings are handled through the VPC's routing and potentially a proxy EC2 instance or a NAT gateway
    // Ensure VPC route table directs traffic via your desired proxy
  }
}

