  zone_id           = aws_route53_zone.primary.zone_id
  name              = "example.com"
  type              = "A"
  ttl               = "60"
  records           = ["192.0.2.20"]
  set_identifier    = "secondary"

  failover_routing_policy {
    type = "SECONDARY"
  }
}

