resource "aws_route53_traffic_policy" "lowest_load_policy" {
  name    = "lowest-load-policy"
  comment = "Route traffic to the endpoint in primary hosted zone with the lowest load in us-east-1 or eu-central-1"

  document = jsonencode({
    "AWSPolicyFormatVersion": "2018-05-17",
    "Rules": {
      "primary-rule": {
        "RuleType": "Failover",
        "Primary": {
          "EndpointReference": "primary-endpoint"
        },
        "EndpointReference": "failover-endpoint"
      },
      "load-based-rule": {
        "RuleType": "Latency",
        "Regions": ["us-east-1", "eu-central-1"],
        "EvaluateTargetHealth": true,
        "EndpointReference": "primary-endpoint"
      }
    },
    "Endpoints": {
      "primary-endpoint": {
        "Type": "elastic-load-balancer",
        "Region": "us-east-1",
        "Value": "my-load-balancer-1.us-east-1.elb.amazonaws.com"
      },
      "failover-endpoint": {
        "Type": "elastic-load-balancer",
        "Region": "eu-central-1",
        "Value": "my-load-balancer-2.eu-central-1.elb.amazonaws.com"
      }
    },
    "StartEndpoint": "primary-endpoint"
  })
}

