provider "aws" {
  region = var.region
}

data "aws_caller_identity" "current" {}

data "aws_ecr_repository" "app_repo" {
  name = var.ecr_repository_name
}

data "aws_ecr_image" "latest_stable" {
  repository_name = data.aws_ecr_repository.app_repo.name
  image_tag       = "stable"
}

locals {
  image_tag      = "stable"
  aws_tags       = merge(var.base_tags, { Environment = terraform.workspace })
  workspace_name = terraform.workspace
}

module "eks" {
  source          = "terraform-aws-modules/eks/aws"
  cluster_name    = var.cluster_name
  cluster_version = var.cluster_version
  subnets         = var.subnets
  vpc_id          = var.vpc_id

  node_groups = [
    {
      name                   = "worker-group"
      instance_types         = var.instance_types
      desired_capacity       = var.desired_node_count
      min_capacity           = var.min_node_count
      max_capacity           = var.max_node

      additional_tags = local.aws_tags
    }
  ]

  cluster_security_group_additional_rules = var.cluster_security_group_rules

  enable_irsa = true

  manage_aws_auth = true
  map_accounts    = var.map_accounts
  map_users       = var.map_users
  map_roles       = var.map_roles

  enable_cluster_log_exports = true
  cluster_log_types          = var.cluster_log_types

  tags = local.aws_tags
}

data "aws_eks_cluster" "cluster" {
  name = module.eks.cluster_id
}

data "aws_eks_cluster_auth" "cluster" {
  name = module.eks.cluster_id
}

provider "kubernetes" {
  host                   = data.aws_eks_cluster.cluster.endpoint
  cluster_ca_certificate = base64decode(data.aws_eks_cluster.cluster.certificate_authority[0].data)

  token = data.aws_eks_cluster_auth.cluster.token

  load_config_file       = false
  version                = "~> 2.0"
}

provider "helm" {
  kubernetes {
    host                   = data.aws_eks_cluster.cluster.endpoint
    cluster_ca_certificate = base64decode(data.aws_eks_cluster.cluster.certificate_authority[0].data)

    token = data.aws_eks_cluster_auth.cluster.token
  }
}

