resource "aws_eks_cluster" "example" {
  name     = "example-eks-cluster"
  role_arn = aws_iam_role.eks_cluster_role.arn

  vpc_config {
    subnet_ids = aws_subnet.example[*].id
  }

  # Ensures the cluster is properly configured for Fargate
  enabled_cluster_log_types = [
    "api",
    "audit",
    "scheduler",
    "controllerManager",
  ]

  depends_on = [
    aws_iam_role_policy_attachment.eks_cluster_policy,
    aws_iam_role_policy_attachment.eks_service_policy
  ]
}

resource "aws_eks_fargate_profile" "kube_system_profile" {
  cluster_name           = aws_eks_cluster.example.name
  fargate_profile_name   = "kube-system-profile"
  pod_execution_role_arn = aws_iam_role.eks_fargate_pod_execution_role.arn

  selector {
    namespace = "kube-system"
  }

  subnet_ids = [
    for subnet in data.aws_subnets.selected.subnets :
    subnet if contains(
      aws_ec2_tag.cluster_subnet_tag[subnet].tags, "kubernetes.io/cluster/${aws_eks_cluster.example.name}"
    )
  ]
}

data "aws_subnets" "selected" {
  filter {
    name   = "vpc-id"
    values = [aws_vpc.main.id]
  }
}

resource "aws_ec2_tag" "cluster_subnet_tag" {
  for_each = toset(data.aws_subnets.selected.subnets)
  key      = "kubernetes.io/cluster/${aws_eks_cluster.example.name}"
  value    = "shared"
  resource_id = each.value
}

resource "null_resource" "patch_coredns" {
  depends_on = [
    aws_eks_cluster.example,
    aws_eks_fargate_profile.kube_system_profile
  ]

  provisioner "local-exec" {
    command = <<EOT
      export KUBECONFIG=./kubeconfig_eks
      cat <<EOF | kubectl apply -f -
      apiVersion: v1
      kind: ConfigMap
      metadata:
        name: coredns-custom
        namespace: kube-system
      data:
        stubs.example: |
          stubzone "example.com" {
            server localhost:53
          }
      EOF

      kubectl patch deployment coredns \n        -n kube-system \n        --type json \n        -p='[{"op": "replace", "path": "/spec/template/spec/containers/0/args", "value": [
          "coredns",
          "-conf",
          "/etc/coredns/Corefile"
        ]}]'
    EOT

    interpreter = ["/bin/bash", "-c"]

    environment = {
      AWS_REGION          = var.aws_region
      KUBE_CONFIG_ENDPOINT        = aws_eks_cluster.example.endpoint
      KUBE_CONFIG_CA_DATA         = aws_eks_cluster.example.certificate_authority[0].data
      KUBE_CONFIG_TOKEN           = data.aws_eks_cluster_auth.eks_auth.token
    }
  }
}

data "aws_eks_cluster_auth" "eks_auth" {
  name = aws_eks_cluster.example.name
}

resource "aws_iam_role" "eks_cluster_role" {
  name = "eks-cluster-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "eks.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "eks_cluster_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSClusterPolicy"
  role       = aws_iam_role.eks_cluster_role.name
}

resource "aws_iam_role_policy_attachment" "eks_service_policy" {
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSServicePolicy"
  role       = aws_iam_role.eks_cluster_origin_role.name
}

resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name                                    = "main-vpc"
    "kubernetes.io/cluster/${aws_eks_cluster.example.name}" = "shared"
  }
}

resource "aws_subnet" "example" {
  count                   = 2
  vpc_id                  = aws_vpc.main.id
  cidr_block              = cidrsubnet(aws_vpc.main.cidr_block, 8, count.index)
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = true

  tags = {
    Name = "subnet-${count.index}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}
