provider "aws" {
  region = "us-west-2"
}

resource "random_string" "bucket_suffix" {
  length  = 8
  special = false
  upper   = false
  number  = true
}

locals {
  logs_bucket_name = "logs-bucket-${random_string.bucket_suffix.result}"
  data_bucket_name = "data-bucket-${random_string.bucket_suffix.result}"
}

resource "aws_s3_bucket" "logs_bucket" {
  bucket = local.logs_bucket_name

  acl = "log-delivery-write"

  tags = {
    Name        = "Log Delivery Bucket"
    Environment = "Dev"
  }
}

resource "aws_s3_bucket" "data_bucket" {
  bucket = local.data_bucket_name

  acl = "private"

  logging {
    target_bucket = aws_s3_bucket.logs_bucket.id
    target_prefix = "data-access-logs/"
  }

  tags = {
    Name        = "Data Bucket"
    Environment = "Dev"
  }
}

resource "aws_s3_bucket_ownership_controls" "logs_ownership" {
  bucket = aws_s3_bucket.logs_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

resource "aws_s3_bucket_ownership_controls" "data_ownership" {
  bucket = aws_s3_bucket.data_bucket.id
  rule {
    object_ownership = "BucketOwnerPreferred"
  }
}

