resource "aws_instance" "example" {
  ami           = data.aws_ami.amazon_linux_2.id
  instance_type = "t3.micro"

  # CPU options - only supported for instances that support CPU options (like C, M, R, etc.)
  # Note: t3.micro does not support changing core/thread count, so we pick appropriate instance type
  # Using m5.large as an example that allows CPU options (2 vCPUs, 2 threads per core by default, but configurable)
  # However, for 2 vCPUs and 2 threads per core, default settings usually reflect actual vCPUs and threads
  # To customize cpu_options, use instance_type that supports it and specify cpu_options

  # Example: Use m5.large (2 vCPUs, 2 threads per core by default)
  instance_type = "m5.large" # This has 2 vCPUs and 2 threads per core by default

  # If you need to explicitly set CPU options (e.g. disable multithreading or set core count)
  # Note: must use instance types that support CPU options
  cpu_options {
    core_count       = 2
    threads_per_core = 2
  }
}

