provider "aws" {
  region = "us-west-2"
}

# Create a VPC
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "main-vpc"
  }
}

# Public subnet
resource "aws_subnet" "public_subnet" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-west-2a"
  map_public_ip_on_launch = true

  tags = {
    Name = "public-subnet"
  }
}

# Private subnet
resource "aws_subnet" "private_subnet" {
  vpc_d                  = aws_vpc.main.id
  cidr_block             = "10.0.2.0/24"
  availability_zone      = "us-west-2a"

  tags = {
    Name = "private-subnet"
  }
}

# Internet Gateway for public access
resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id

  tags = {
    Name = "main-gateway"
  }
}

# Route Table for public subnet
resource "aws_route_table" "public_rt" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.gw.id
  }

  tags = {
    Name = "public-route-table"
  }
}

# Associate public subnet with public route table
resource "aws_route_table_association" "public_assoc" {
  subnet_id      = aws_subnet.public_subnet.id
  route_table_id = aws_route_table.public_rt.id
}

# Placement Group with cluster strategy
resource "aws_placement_group" "cluster_pg" {
  name     = "cluster-placement-group"
  strategy = "cluster"
}

# EC2 Key Pair (assuming you have a public key)
# resource "aws_key_pair" "deployer" {
#   key_name   = "deployer-key"
#   public_key = "ssh-rsa YOUR_PUBLIC_KEY_HERE"
# }

# EC2 Instances in cluster placement group
resource "aws_instance" "instance1" {
  ami                    = "ami-0c02fb55956c7d316" # Amazon Linux 2 in us-west-2
  instance_type          = "t3.micro"
  subnet_id              = aws_subnet.public_subnet.id
  placement_group        = aws_placement_group.cluster_pg.name
  key_name               = "deployer-key" # Uncomment key resource above if using
  vpc_security_group_ids = [aws_security_group.instance_sg.id]

  tags = {
    Name = "instance1"
  }
}

resource "aws_instance" "instance2" {
  ami                    = "ami-0c02fb55956c7d316"
  instance_type          = "t3.micro"
  subnet_id              = aws_subnet.public_subnet.id
  placement_group        = aws_placement_group.cluster_pg.name
  key_name               = "deployer-key"
  vpc_security_group_ids = [aws_security_group.instance_sg.id]

  tags = {
    Name = "instance2"
  }
}

resource "aws_instance" "instance3" {
  ami                    = "ami-0c02fb55956c7d316"
  instance_type          = "t3.micro"
  subnet_id              = aws_subnet.public_subnet.id
  placement_group        = aws_placement_group.cluster_pg.name
  key_name               = "deployer-key"
  vpc_security_group_ids = [aws_security_group.instance_sg.id]

  tags = {
    Name = "instance3"
  }
}

# Security group allowing SSH and internal traffic
resource "aws_security_group" "instance_sg" {
  name        = "instance-security-group"
  description = "Allow SSH and internal traffic"
  vpc_id      = aws_vpc.main.id

  # Allow SSH from anywhere (consider restricting in production)
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

