extracted_code:
resource "aws_redshift_cluster" "example" {
  cluster_identifier        = "example-cluster"
  database_name             = "exampledb"
  master_username           = "exampleuser"
  master_password           = "examplepass123"
  node_type                 = "dc2.large"
  cluster_type              = "single-node"
  automated_snapshot_retention_period = 7
  cluster_subnet_group_name = aws_redshift_subnet_group.example.name
  skip_final_snapshot       = true

  # Enable periodic snapshots every 12 hours via backup window (daily)
  preferred_maintenance_window = "sun:04:00-sun:04:30"
  preferred_backup_window      = "03:00-03:30"  # Triggers daily snapshot; use with cron or event bridge for 12hr

  # Note: Redshift only supports one automatic snapshot per day via `preferred_backup_window`.
  # For true 12-hour snapshots, combine with AWS Backup or EventBridge + Lambda.
}

resource "aws_redshift_subnet_group" "example" {
  name        = "example-subnet-group"
  description = "Subnet group for Redshift cluster"
  subnet_ids  = aws_subnet.example[*].id
}

# Example subnets (adjust according to your VPC)
resource "aws_subnet" "example" {
  count                   = 2
  vpc_id                  = aws_vpc.example.id
  cidr_block              = count.index == 0 ? "10.0.1.0/24" : "10.0.2.0/24"
  availability_zone       = data.aws_availability_zones.available.names[count.index]
  map_public_ip_on_launch = false
}

resource "aws_vpc" "example" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "example-vpc"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

# To achieve 12-hour snapshots, you may create an AWS Backup plan
resource "aws_backup_plan" "example" {
  name = "redshift-12hour-backup"

  rule {
    rule_name         = "12hour-backup-rule"
    target_vault_name = aws_backup_vault.example.name
    schedule          = "cron(0 */12 * * ? *)"  # Every 12 hours
    start_window_minutes = 60
    completion_window_minutes = 180

    lifecycle {
      delete_after = 7
    }
  }
}

resource "aws_backup_vault" "example" {
  name = "redshift-backup-vault"
}

resource "aws_backup_selection" "example" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "redshift-selection"
  plan_id      = aws_backup_plan.example.id

  resources = [aws_redshift_cluster.example.arn]
}

resource "aws_iam_role" "backup_role" {
  name = "backup-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "backup_policy" {
  name = "backup-policy"
  role = aws_iam_role.backup_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:DeleteObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.backup_bucket.arn,
          "${aws_s3_bucket.backup_bucket.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:DescribeVolumes",
          "ec2:DescribeSnapshots",
          "ec2:CreateTags",
          "ec2:DeleteTags",
          "ec2:CreateVolume",
          "ec2:CopySnapshot",
          "ec2:DescribeTags"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "kms:Encrypt",
          "kms:Decrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:DescribeKey"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "redshift:DescribeClusters",
          "redshift:CreateClusterSnapshot",
          "redshift:DeleteClusterSnapshot"
        ]
        Resource = aws_redshift_cluster.example.arn
      }
    ]
  })
}

resource "aws_s3_bucket" "backup_bucket" {
  bucket = "redshift-backup-bucket-example-unique"
  force_destroy = true
}

