# Define required providers
provider "aws" {
  region = "us-west-2" # Change to your desired region
}

# Create an IAM role for Redshift
resource "aws_iam_role" "redshift_role" {
  name = "redshift-s3-access-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "redshift.amazonaws.com"
        }
      }
    ]
  })
}

# Attach AmazonS3ReadOnlyAccess policy to the role (modify as needed)
resource "aws_iam_role_policy_attachment" "redshift_s3_access" {
  role       = aws_iam_role.redshift_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

# Create Redshift cluster
resource "aws_redshift_cluster" "example" {
  cluster_identifier        = "example-redshift-cluster"
  database_name             = "exampledb"
  master_username           = "adminuser"
  master_password           = "examplePassword123"
  node_type                 = "dc2.large"
  cluster_type              = "single-node"
  allow_version_upgrade     = true
  publicly_accessible       = false
  skip_final_snapshot       = true
  iam_roles                 = [aws_iam_role.redshift_role.arn]
  availability_zone_relocation_enabled = true
}

# Optional: Output the cluster endpoint
output "redshift_endpoint" {
  value = aws_redshift_cluster.example.endpoint
}

output "iam_role_arn" {
  value = aws_iam_role.redshift_role.arn
}
