    name = "id"
    type = "S"
  }

  global_secondary_index {
    name               = "replica-index"
    hash_key           = "id"
    projection_type    = "ALL"
    non_key_attributes = []
  }

  point_in_time_recovery {
    enabled = true
  }

  # Enable DynamoDB global table (replication across regions)
  replica {
    region_name = var.replica_region
  }
}

# Variable to specify the replica region
