resource "aws_sagemaker_pipeline" "example_pipeline" {
  pipeline_name = "example-sagemaker-pipeline"

  pipeline_definition = jsonencode({
    Version = "2020-12-01"
    Metadata = {}
    Parameters = [
      {
        Name        = "TrainingInstanceType"
        Type        = "String"
        DefaultValue = "ml.m5.xlarge"
        Description = "The type of instance to use for training"
      },
      {
        Name        = "TrainingInstanceCount"
        Type        = "Integer"
        DefaultValue = 1
        Description  = "The number of instances to use for training"
      }
    ]
    Steps = [
      {
        Name = "ProcessingStep"
        Type = "Processing"
        Arguments = {
          AppSpecification = {
            ImageUri = "683313688378.dkr.ecr.us-west-2.amazonaws.com/sagemaker-scikit-learn:0.23-1-cpu-py3"
          }
          ProcessingInputs = [
            {
              InputName = "input-1"
              S3Input = {
                LocalPath        = "/opt/ml/processing/input"
                S3Uri            = "s3://my-bucket/input-data"
                S3DataType       = "S3Prefix"
                S3InputMode      = "File"
                S3DataDistributionType = "FullyReplicated"
                S3CompressionType = "None"
              }
            }
          ]
          ProcessingOutputs = [
            {
              OutputName = "output-1"
              S3Output = {
                LocalPath      = "/opt/ml/processing/output"
                S3Uri          = "s3://my-bucket/processed-data"
                S3UploadMode   = "EndOfJob"
              }
            }
          ]
          ProcessingResources = {
            ClusterConfig = {
              InstanceCount = 1
              InstanceType  = "ml.m5.large"
              VolumeSizeInGB = 30
            }
          }
          RoleArn = aws_iam_role.sagemaker_role.arn
        }
      },
      {
        Name = "TrainingStep"
        Type = "Training"
        Arguments = {
          AlgorithmSpecification = {
            TrainingImage          = "683313688378.dkr.ecr.us-west-2.amazonaws.com/sagemaker-xgboost:1.0-1-cpu-py3"
            TrainingInputMode      = "File"
          }
          RoleArn = aws_iam_role.sagemaker_role.arn
          InputDataConfig = [
            {
              ChannelName = "train"
              DataSource = {
                S3DataSource = {
                  S3DataType     = "S3Prefix"
                  S3Uri          = "s3://my-bucket/processed-data/train"
                  S3DataDistributionType = "FullyReplicated"
                }
              }
              ContentType = "text/csv"
              CompressionType = "None"
              RecordWrapperType = "None"
            }
          ]
          OutputDataConfig = {
            S3OutputPath = "s3://my-bucket/trained-model"
          }
          ResourceConfig = {
            InstanceType     = "${TrainingInstanceType}"
            InstanceCount    = "${TrainingInstanceCount}"
            VolumeSizeInGB   = 10
          }
          StoppingCondition = {
            MaxRuntimeInSeconds = 3600
          }
          HyperParameters = {
            "max_depth"           = "5"
            "eta"                 = "0.2"
            "gamma"               = "4"
            "min_child_weight"    = "6"
            "subsample"           = "0.8"
            "silent"              = "0"
            "objective"           = "reg:linear"
            "num_round"           = "100"
          }
        }
      },
      {
        Name = "ModelStep"
        Type = "Model"
        Arguments = {
          ModelName = "${aws_sagemaker_pipeline.example_pipeline.pipeline_name}-model"
          PrimaryContainer = {
            Image  = "683313688378.dkr.ecr.us-west-2.amazonaws.com/sagemaker-xgboost:1.0-1-cpu-py3"
            ModelDataUrl = "${Step.Training.TrainingJobArn}/output/model.tar.gz"
          }
          ExecutionRoleArn = aws_iam_role.sagemaker_role.arn
        }
      },
      {
        Name = "EndpointConfigStep"
        Type = "EndpointConfig"
        Arguments = {
          EndpointConfigName = "${aws_sagemaker_pipeline.example_pipeline.pipeline_name}-config"
          ProductionVariants = [
            {
              VariantName     = "variant-1"
              ModelName       = "${aws_sagemaker_pipeline.example_pipeline.pipeline_name}-model"
              InstanceType    = "ml.m5.large"
              InitialInstanceCount = 1
            }
          ]
        }
      },
      {
        Name = "EndpointStep"
        Type = "Endpoint"
        Arguments = {
          EndpointName = "${aws_sagemaker_pipeline.example_pipeline.pipeline_name}-endpoint"
          EndpointConfigName = "${aws_sagemaker_pipeline.example_pipeline.pipeline_name}-config"
        }
        Parameters = {
          CreateEndpoint = "True"
        }
      }
    ]
  })

  role_arn = aws_iam_role.sagemaker_role.arn

  tags = {
    Environment = "dev"
    Project     = "mlops"
  }
}

