extracted_code:
provider "aws" {
  region = "us-east-1" # Note: There is no "us-east-2" region; using "us-east-1" as the closest valid region
}

resource "aws_vpc" "msk_vpc" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "msk-vpc"
  }
}

resource "aws_subnet" "msk_subnets" {
  count = 3

  vpc_id            = aws_vpc.msk_vpc.id
  cidr_block        = cidrsubnet(aws_vpc.msk_vpc.cidr_block, 8, count.index)
  availability_zone = element(data.aws_availability_zones.available.names, count.index)

  tags = {
    Name = "msk-subnet-${count.index}"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_security_group" "msk_security_group" {
  vpc_id = aws_vpc.msk_vpc.id

  # Allow TLS communication on port 9094 (MSK client)
  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow TLS zookeeper client connections on port 2181
  ingress {
    from_port   = 2181
    to_port     = 2181
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow all egress
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk-security-group"
  }
}

resource "aws_msk_cluster" "example" {
  cluster_name           = "example-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type   = "kafka.m5.large"
    client_subnets  = aws_subnet.msk_subnets[*].id
    security_groups = [aws_security_group.msk_security_group.id]
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.example.arn
  }

  tags = {
    Name = "example-msk-cluster"
  }
}

resource "aws_kms_key" "example" {
  description             = "Customer managed CMK for MSK encryption"
  deletion_window_in_days = 7
}

