    security_groups = [aws_security_group.msk_security_group.id]
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.example.arn
  }

  tags = {
    Name = "example-msk-cluster"
  }
}

resource "aws_kms_key" "example" {
  description             = "Customer managed CMK for MSK encryption"
  deletion_window_in_days = 7
}
