provider "aws" {
  region = "us-east-1"
}

resource "aws_cloudwatch_log_group" "msk_logs" {
  name = "/aws/msk/terraform-msk-cluster"
}

resource "aws_s3_bucket" "msk_logs" {
  bucket = "terraform-msk-logs-bucket"
}

resource "aws_kinesis_firehose_delivery_stream" "msk_logs" {
  name        = "terraform-msk-logs-delivery-stream"
  destination = "s3"

  s3_configuration {
    bucket_arn = aws_s3_bucket.msk_logs.arn
    role_arn   = aws_iam_role.firehose_role.arn
  }
}

resource "aws_iam_role" "firehose_role" {
  name = "firehose_delivery_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose_s3_policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Resource = [
          aws_s3_bucket.msk_logs.arn,
          "${aws_s3_bucket.msk_logs.arn}/*"
        ]
      }
    ]
  })
}

resource "aws_kms_key" "msk_encryption" {
  description = "KMS key for MSK cluster encryption at rest"
  enable_key_rotation = true
}

resource "aws_security_group" "msk_sg" {
  name        = "terraform-msk-security-group"
  description = "Security group for MSK brokers"

  ingress {
    from_port   = 2181
    to_port     = 2181
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 9094
    to_port     = 9094
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_subnet" "msk_subnets" {
  count = 3

  vpc_id            = aws_vpc.main.id
  availability_zone = "us-east-1${element(["a", "b", "c"], count.index)}"
  cidr_block        = "10.0.${count.index}.0/24"

  tags = {
    Name = "terraform-msk-subnet-${count.index}"
  }
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "terraform-msk-vpc"
  }
}

resource "aws_msk_cluster" "example" {
  cluster_name           = "terraform-msk-cluster"
  kafka_version          = "3.5.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type = "kafka.m5.large"
    client_subnets = aws_subnet.msk_subnets[*].id
    security_groups = [aws_security_group.msk_sg.id]
  }

  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_encryption.arn
  }

  open_monitoring {
    prometheus {
      jmx_exporter {}
      node_exporter {}
    }
  }

  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_logs.name
      }

      firehose {
        enabled         = true
        delivery_stream = aws_kinesis_firehose_delivery_stream.msk_logs.name
      }

      s3 {
        enabled = true
        bucket  = aws_s3_bucket.msk_logs.bucket
        prefix  = "msk-logs"
      }
    }
  }

  tags = {
    Environment = "test"
  }
}

