provider "aws" {
  region = "us-west-2" # Default region; can be changed as needed
}

data "aws_availability_zones" "available" {
  state = "available"
}

resource "aws_db_subnet_group" "mysql_subnet_group" {
  name       = "mysql-subnet-group"
  subnet_ids = aws_subnet.mysql_subnets[*].id

  tags = {
    Name = "MySQL Subnet Group"
  }
}

resource "aws_subnet" "mysql_subnets" {
  for_each = toset(data.aws_availability_zones.available.names)

  vpc_id            = aws_vpc.main.id
  cidr_block        = cidrsubnet(aws_vpc.main.cidr_block, 8, index(data.aws_availability_zones.available.names, each.value))
  availability_zone = each.value

  tags = {
    Name = "MySQL Subnet ${each.value}"
  }
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "MySQL VPC"
  }
}

resource "aws_rds_cluster" "mysql_cluster" {
  cluster_identifier              = "mysql-cluster"
  engine                          = "aurora-mysql"
  engine_version                  = "8.0.mysql_aurora.3.03.0"
  master_username                 = "admin"
  master_password                 = "securepassword123"
  backup_retention_period         = 7
  preferred_backup_window         = "02:00-03:00"
  db_subnet_group_name            = aws_db_subnet_group.mysql_subnet_group.name
  vpc_security_group_ids          = [aws_security_group.mysql_sg.id]
  skip_final_snapshot             = true
  storage_encrypted               = true
  enabled_cloudwatch_logs_exports = ["error", "general", "slowquery"]

  # Ensure instance is created in each availability zone
  for_each = toset(data.aws_availability_zones.available.names)

  serverlessv2_scaling_configuration {
    min_capacity = 0.5
    max_capacity = 16.0
  }
}

resource "aws_rds_cluster_instance" "cluster_instances" {
  for_each = aws_rds_cluster.mysql_cluster

  identifier             = "mysql-cluster-instance-${each.key}"
  cluster_identifier     = each.value.id
  instance_class         = "db.r6g.large"
  engine                 = each.value.engine
  engine_version         = each.value.engine_version
  db_subnet_group_name   = aws_db_subnet_group.mysql_subnet_group.name
  availability_zone      = each.key
  publicly_accessible    = false

  skip_final_snapshot    = true
}

resource "aws_security_group" "mysql_sg" {
  vpc_id = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"] # Adjust as needed for allowed CIDRs
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "MySQL Security Group"
  }
}

# Note: Aurora Serverless v2 or Provisioned clusters auto-scale storage,
# but minimum storage size is managed via allocation.
# To ensure 100 GB per AZ, we rely on initial load and monitoring,
# or use provisioned with sufficient I/O demand to grow storage.
# RDS Aurora auto-allocates storage up to 128 TiB; 100 GB per AZ is within default behavior.
# Manual storage size setting not applicable for Aurora clusters (grows automatically).
# For fixed 100 GB per instance, consider modifying with monitoring/alerting.

