  ]

  parameter_group_name = aws_redshift_parameter_group.sample.name
}

resource "aws_security_group" "redshift_sg" {
  name        = "redshift-sg"
  description = "Security group for Redshift cluster"

  ingress {
    from_port   = 5439
    to_port     = 5439
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "Redshift Security Group"
  }
}

resource "aws_redshift_event_subscription" "example" {
  name          = "redshift-event-subscription"
  sns_topic_arn = aws_sns_topic.redshift_events.arn
  source_type   = "parameter-group"

  source_ids = [
    aws_redshift_parameter_group.sample.id
  ]

  event_categories = [
