extracted_code:
resource "aws_s3_bucket" "example_bucket" {
  bucket = "my-unique-bucket-name-12345"

  # Enable requester pays setting - this makes requester (not bucket owner) pay for requests and data transfer
  # But since we want the *bucket owner* to be responsible for all charges, we leave requester_pays = false (default)

  # By not setting requester_pays = true, the bucket owner pays for requests and data transfer costs
  # Storage costs are always paid by the bucket owner

  # Example block for explicit clarity (optional, as false is default)
  requester_pays = false

  # Optional: Add tags
  tags = {
    Name        = "example-bucket"
    Environment = "production"
  }
}

# Optional: Enable bucket owner enforced access controls to ensure bucket owner owns all data ownership (recommended)
resource "aws_s3_bucket_ownership_controls" "ownership" {
  bucket = aws_s3_bucket.example_bucket.id
  rule {
    object_ownership = "BucketOwnerEnforced"
  }
}

