```hcl
```hcl
# Autograding system using AWS CodeBuild, GitHub integration, and S3 for artifact storage

provider "aws" {
  region = "us-east-1"
}

# S3 bucket to store build artifacts and grading reports
resource "aws_s3_bucket" "autograding_artifacts" {
  bucket = "cs-course-autograding-artifacts-${random_id.suffix.hex}"
  force_destroy = true

  versioning {
    enabled = true
  }

  lifecycle {
    prevent_destroy = false
  }
}

# Random suffix to ensure unique bucket name
resource "random_id" "suffix" {
  byte_length = 4
}

# IAM role for CodeBuild to access S3 and CloudWatch
resource "aws_iam_role" "codebuild_role" {
  name = "codebuild-autograding-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect = "Allow",
        Principal = {
          Service = "codebuild.amazonaws.com"
        },
        Action = "sts:AssumeRole"
      }
    ]
  })
}

# IAM policy for CodeBuild permissions
resource "aws_iam_policy" "codebuild_policy" {
  name = "codebuild-autograding-policy"
  description = "Policy for CodeBuild to access S3, CloudWatch, and GitHub"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ],
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow",
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:PutObjectAcl"
        ],
        Resource = "${aws_s3_bucket.autograding_artifacts.arn}/*"
      },
      {
        Effect = "Allow",
        Action = [
          "s3:GetBucketPolicy",
          "s3:PutBucketPolicy"
        ],
        Resource = aws_s3_bucket.autograding_artifacts.arn
      }
    ]
  })
}

# Attach the policy to the role
resource "aws_iam_role_policy_attachment" "codebuild_policy_attach" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}

# CodeBuild project for autograding
resource "aws_codebuild_project" "autograding_project" {
  name          = "cs-autograding-project"
  description   = "Auto-grading student submissions from GitHub"
  build_timeout = 30
  queued_timeout = 60
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    location = aws_s3_bucket.autograding_artifacts.bucket
    packaging = "ZIP"
    path = "grades"
  }

  cache {
    type = "S3"
    location = aws_s3_bucket.autograding_artifacts.bucket
  }

  environment {
    type            = "LINUX_CONTAINER"
    image           = "aws/codebuild/standard:5.0"
    compute_type    = "BUILD_GENERAL1_SMALL"
    image_pull_credentials_type = "CODEBUILD"

    environment_variable {
      name  = "STUDENT_REPO_URL"
      value = "https://github.com/${var.github_owner}/${var.github_repo}.git"
      type  = "PLAINTEXT"
    }

    environment_variable {
      name  = "GRADING_SCRIPT"
      value = "python3 grade.py"
      type  = "PLAINTEXT"
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/${var.github_owner}/${var.github_repo}"
    git_clone_depth = 1
    report_build_status = true
    buildspec = "buildspec.yml"
  }

  tags = {
    Project = "CS-Autograding"
    Course = var.course_id
  }
}

# Buildspec file template to be stored in student repos or provided externally
# This would typically be versioned in the student repo or fetched during build
# Example buildspec.yml content:
# version: 0.2
# phases:
#   install:
#     commands:
#       - echo "Installing grading dependencies..."
#       - pip install -r requirements.txt
#   pre_build:
#     commands:
#       - echo "Preparing code for grading..."
#   build:
#     commands:
#       - echo "Running autograder..."
#       - $GRADING_SCRIPT
#   post_build:
#     commands:
#       - echo "Uploading results..."
#       - aws s3 cp grade_report.txt s3://$ARTIFACTS_BUCKET/grades/$CODEBUILD_BUILD_ID/
# artifacts:
#   files:
#     - grade_report.txt

# Variables for GitHub and course details
variable "github_owner" {
  description = "GitHub organization or user name hosting student repositories"
  type        = string
}

variable "github_repo" {
  description = "Base name of the student repository (may use wildcards or be overridden per student)"
  type        = string
}

variable "course_id" {
  description = "Course identifier for tagging and organization"
  type        = string
  default     = "CS101"
}

output "autograding_project_name" {
  value = aws_codebuild_project.autograding_project.name
}

output "artifacts_bucket" {
  value = aws_s3_bucket.autograding_artifacts.bucket_domain_name
}

output "codebuild_webhook_url" {
  value = aws_codebuild_project.autograding_project.webhook.url
}
```
