resource "aws_iam_role_policy_attachment" "codebuild_s3" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonS3FullAccess"
}

resource "aws_iam_role_policy_attachment" "codebuild_logs" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/CloudWatchLogsFullAccess"
}

resource "aws_iam_role_policy_attachment" "codebuild_ecr" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSCodeCommitPowerUser"
}

# CodeBuild project for running autograding
resource "aws_codebuild_project" "autograder" {
  name         = "cs-autograder"
  description  = "Automated grader for student programming assignments"
  service_role = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    location = aws_s3_bucket.student_submissions.bucket
    path = "artifacts"
    packaging = "ZIP"
  }

  cache {
    type  = "S3"
    location = "${aws_s3_bucket.student_submissions.bucket}/cache"
  }

  environment {
    type            = "LINUX_CONTAINER"
    image           = "aws/codebuild/standard:5.0"
    compute_type    = "BUILD_GENERAL1_SMALL"
    privileged_mode = true

    environment_variable {
      name  = "GITHUB_TOKEN"
      value = var.github_token
      type  = "PLAINTEXT"
    }

    environment_variable {
      name  = "S3_BUCKET"
      value = aws_s3_bucket.student_submissions.bucket
      type  = "PLAINTEXT"
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/${var.course_organization}/${var.assignment_repo}.git"
    git_clone_depth = 1
    report_build_status = true
  }

  logs_config {
    cloudwatch_logs {
      group_name  = "/aws/codebuild/cs-autograder"
      stream_name = "main"
    }
    s3_logs {
      status   = "ENABLED"
      location = "${aws_s3_bucket.student_submissions.bucket}/logs"
    }
  }

  build_timeout = 60
  queued_timeout = 30

  tags = {
    Project = "CS-Autograding"
  }
}

# CloudWatch Events to trigger CodeBuild on GitHub push (via CloudWatch Events and CodeBuild)
resource "aws_cloudwatch_event_rule" "github_push_trigger" {
  name        = "github-push-trigger"
  description = "Triggers autograding on GitHub push"
  event_pattern = jsonencode({
    source      = ["aws.codecommit"]
    detail-type = ["CodeCommit Repository State Change"]
    detail = {
      event       = ["referenceCreated", "referenceUpdated"]
      referenceType = ["branch"]
      referenceName = ["main", "master", "submission"]
    }
  })
}

resource "aws_cloudwatch_event_target" "codebuild_target" {
  rule      = aws_cloudwatch_event_rule.github_push_trigger.name
  target_id = "codebuild"
  arn       = aws_codebuild_project.autograder.arn
}

# SNS topic for notifying instructors about grading results
resource "aws_sns_topic" "grading_notifications" {
  name = "autograding-results"
}

resource "aws_sns_topic_subscription" "instructor_email" {
  topic_arn = aws_sns_topic.grading_notifications.arn
  protocol  = "email"
  endpoint  = var.instructor_email
}

# Integrate SNS with CodeBuild via EventBridge to publish grading completion
resource "aws_cloudwatch_event_rule" "grading_completed" {
  name        = "grading-completed"
  description = "Notifies when grading is complete"
  event_pattern = jsonencode({
    source      = ["aws.codebuild"]
    detail-type = ["CodeBuild Build State Change"]
    detail = {
      "build-status" = ["SUCCEEDED", "FAILED"]
      project-name   = [aws_codebuild_project.autograder.name]
    }
  })
}

resource "aws_cloudwatch_event_target" "sns_notification" {
  rule      = aws_cloudwatch_event_rule.grading_completed.name
  target_id = "sns"
  arn       = aws_sns_topic.grading_notifications.arn
}

# Random suffix to ensure unique S3 bucket name
resource "random_string" "suffix" {
  length  = 8
  special = false
  upper   = false
}

# Variables used (to be provided via terraform.tfvars or CLI)
variable "github_token" {
  description = "GitHub personal access token for cloning private repos"
  type        = string
  sensitive   = true
}

variable "course_organization" {
  description = "GitHub organization or username where student repos are hosted"
  type        = string
}

variable "assignment_repo" {
  description = "Base repository name pattern or template for student assignments"
  type        = string
}

variable "instructor_email" {
  description = "Email address for receiving grading completion notifications"
  type        = string
}
