resource "aws_codebuild_project" "autograding_project" {
  name         = "cs-course-autograding"
  description  = "Automated grading of student GitHub submissions"
  service_role = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    location = aws_s3_bucket.autograding_artifacts.bucket
    path     = "build-output"
    packaging = "ZIP"
  }

  cache {
    type = "S3"
    location = aws_s3_bucket.autograding_artifacts.bucket
  }

  environment {
    type                = "LINUX_CONTAINER"
    image               = "aws/codebuild/amazonlinux2-x86_64-standard:3.0"
    compute_type        = "BUILD_GENERAL1_SMALL"
    privileged_mode     = true

    environment_variable {
      name  = "GITHUB_REPO"
      value = "student-submission-repo"
      type  = "PLAINTEXT"
    }

    environment_variable {
      name  = "ARTIFACT_BUCKET"
      value = aws_s3_bucket.autograding_artifacts.bucket
      type  = "PLAINTEXT"
    }
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/organization/student-submissions.git"
    git_clone_depth = 1

    buildspec = <<EOF
version: 0.2
phases:
  install:
    commands:
      - echo "Installing grading dependencies"
      - yum update -y
      - yum install -y python3 git
      - pip3 install pytest pylint
  pre_build:
    commands:
      - echo "Fetching student submission"
      - git clone $GITHUB_REPO student-code
  build:
    commands:
      - echo "Running autograding suite"
      - cd student-code
      - pytest --junitxml=../grading-results.xml
      - pylint --output-format=parseable . > ../pylint-output.txt
  post_build:
    commands:
      - echo "Uploading grading results"
      - aws s3 cp ../grading-results.xml s3://$ARTIFACT_BUCKET/grading/$CODEBUILD_BUILD_ID/results.xml
      - aws s3 cp ../pylint-output.txt s3://$ARTIFACT_BUCKET/grading/$CODEBUILD_BUILD_ID/lint.txt
artifacts:
  files:
    - grading-results.xml
    - pylint-output.txt
EOF
  }

  logs_config {
    cloudwatch_logs {
      group_name = "/aws/codebuild/cs-course-autograding"
      stream_name = "build"
    }
    s3_logs {
      status   = "ENABLED"
      location = "${aws_s3_bucket.autograding_artifacts.bucket}/logs"
    }
  }
}

resource "aws_cloudwatch_log_group" "codebuild_logs" {
  name = "/aws/codebuild/cs-course-autograding"
  retention_in_days = 7
}

