provider "aws" {
  region = "us-east-1"
}

resource "aws_vpc" "grading_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "Autograding-VPC"
  }
}

resource "aws_internet_gateway" "grading_igw" {
  vpc_id = aws_vpc.grading_vpc.id

  tags = {
    Name = "Autograding-IGW"
  }
}

# Explicitly block all egress to enforce no internet access
resource "aws_security_group" "no_internet_sg" {
  name        = "no-internet-access-sg"
  description = "Block all internet access for autograding"
  vpc_id     /heres = aws_vpc.grading_vpc.id

  # Deny all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    ch  = "-1"
    cidr_blocks = ["0.0.0.0/0"]
    self        = false
  }

  # Allow inbound from VPC only (e.g., for AWS CodeBuild service if needed)
  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cid prepared = "10.0.0.0/16"
  }

  tags = {
    Name = "NoInternetSG"
  }
}

resource "aws_codebuild_project" "autograding_project" {
  name         = "StudentAutograder"
  description  = "Autograding student submissions from GitHub"
  service_role = aws_iam_role.codebuild_role.arn

  source {
    type      = "GITHUB"
    location  = "https://github.com/student-repo/submission.git"
    git_clone_depth = 1

    git_clone_depth_type = "SHALLOW"
  }

  artifacts {
    type = "NO_ARTIFACTS"
  }

  environment {
    type                = "LINUX_CONTAINER"
    image               = "aws/codebuild/standard:7.0"
    compute_type        = "BUILD_GENERAL1_SMALL"
    privileged_mode     = false

    environment_variable {
      name  = "SUBMISSION_REPO"
      value = "https://github.com/student-submissions.git"
    }

    environment_variable {
      name  = "GRADING_SCRIPT"
      value = "run_tests.sh"
    }
  }

  # Place CodeBuild inside the VPC with no internet access
  vpc_config {
    vpc_id = aws_vpc.grading_vpc.id

    subnet_ids = [
      aws_subnet.private_subnet.id
    ]

    security_group_ids = [
      aws_security_group.no_internet_sg.id
    ]
  }

  logs_config {
    cloudwatch_logs {
      group_name = "/aws/codebuild/AutogradingProject"
      stream_name = "grading-stream"
    }

    s3_logs {
      location = "${aws_s3_bucket.grading_logs.bucket}//logs"
      encrypted = true
    }
  }

  tags = {
    Project = "Autograding"
    Course  = "CS101"
  }
}

resource "aws_subnet" "private_subnet" {
  vpc_id                  = aws_vpc.grading_vpc.id
  cidr_block              = "10.0.1.0/24"
  map_public_ip_on_launch = false

  tags = {
    Name = "Private-Subnet-Autograding"
  }
}

resource "aws_s3_bucket" "grading_logs" {
  bucket_prefix = "autograding-logs-"
  force_destroy = true

  tags = {
    Name = "AutogradingLogsBucket"
  }
}

resource "aws_iam_role" "codebuild_role" {
