  tags = {
    Name = "Autograding-VPC"
  }
}

resource "aws_internet_gateway" "grading_igw" {
  vpc_id = aws_vpc.grading_vpc.id

  tags = {
    Name = "Autograding-IGW"
  }
}

# Explicitly block all egress to enforce no internet access
resource "aws_security_group" "no_internet_sg" {
  name        = "no-internet-access-sg"
  description = "Block all internet access for autograding"
  vpc_id     /heres = aws_vpc.grading_vpc.id

  # Deny all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    ch  = "-1"
    cidr_blocks = ["0.0.0.0/0"]
    self        = false
  }

  # Allow inbound from VPC only (e.g., for AWS CodeBuild service if needed)
  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cid prepared = "10.0.0.0/16"
  }

