  bucket = aws_s3_bucket.grading_outputs.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_iam_role" "codebuild_role" {
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "codebuild.amazonaws.com"
        }
      },
    ]
  })

  tags = {
    Name = "codebuild-service-role"
  }
}

resource "aws_iam_policy" "codebuild_policy" {
  name        = "autograding-codebuild-policy"
  description = "Policy for CodeBuild to access S3 and run in VPC"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.student_submissions.arn,
          "${aws_s3_bucket.student_submissions.arn}/*",
          aws_s3_bucket.grading_outputs.arn,
          "${aws_s3_bucket.grading_outputs.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:CreateNetworkInterface",
          "ec2:DescribeDhcpOptions",
          "ec2:DescribeNetworkInterfaces",
          "ec2:DeleteNetworkInterface",
          "ec2:DescribeSubnets",
          "ec2:DescribeSecurityGroups",
          "ec2:DescribeVpcs"
        ]
        Resource = "*"
      },
      {
        Effect = "Allow"
        Action = [
          "ec2:AssignPrivateIpAddresses",
          "ec2:UnassignPrivateIpAddresses"
        ]
        Resource = "*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_policy_attach" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = aws_iam_policy.codebuild_policy.arn
}

resource "aws_codebuild_project" "autograding_project" {
  name         = "autograding-codebuild-project"
  description  = "Autograding project for student submissions"
  service_role = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    location = aws_s3_bucket.grading_outputs.bucket
    path   = "outputs"
    name   = "grading-result.zip"
    packaging = "ZIP"
  }

  source {
    type      = "GITHUB"
    location  = "https://github.com/your-org/student-repo.git" # Placeholder - can be dynamic
    git_clone_depth = 1
    buildspec = "buildspec.yml" # Define your grading script in buildspec
  }

  environment {
    type                = "LINUX_CONTAINER"
    image               = "aws/codebuild/standard:5.0"
    compute_type        = "BUILD_GENERAL1_SMALL"
    privileged_mode     = false # Disable container access to host, extra sandboxing
  }

  vpc_config {
    vpc_id             = aws_vpc.autograding_vpc.id
    subnets            = [aws_subnet.private_subnet.id]
    security_group_ids = [aws_security_group.codebuild_sg.id]
  }

  logs_config {
    cloudwatch_logs {
      group_name = "/aws/codebuild/autograding-project"
      stream_name = "main"
    }
    s3_logs {
      status   = "ENABLED"
      location = "${aws_s3_bucket.grading_outputs.bucket}/logs"
    }
  }

  tags = [
    {
      key   = "Project"
      value = "Autograding"
    }
  ]
}

resource "aws_cloudwatch_log_group" "codebuild_logs" {
  name              = "/aws/codebuild/autograding-project"
  retention_in_days = 7
}

# Optional: SNS Topic for grading completion notifications
resource "aws_sns_topic" "grading_completion_topic" {
  name = "autograding-completion-notifications"
}

output "student_submissions_bucket" {
  value = aws_s3_bucket.student_submissions.bucket_domain_name
}

output "grading_outputs_bucket" {
  value = aws_s3_bucket.grading_outputs.bucket_domain_name
}

output "codebuild_project_name" {
  value = aws_codebuild_project.autograding_project.name
}

output "vpc_id" {
  value = aws_vpc.autograding_vpc.id
}
