terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }

  backend "s3" {
    bucket = "terraform-state-catapp"
    key    = "prod/catapp/terraform.tfstate"
    region = "us-east-1"
  }
}

provider "aws" {
  region = "us-east-1"
}

# S3 bucket to store cat images
resource "aws_s3_bucket" "cat_images" {
  bucket        = "cat-images-store-${random_string.suffix.result}"
  force_destroy = true
}

resource "aws_s3_bucket_versioning" "cat_images" {
  bucket = aws_s3_bucket.cat_images.id
  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_acl" "cat_images" {
  bucket = aws_s3_bucket.cat_images.id
  acl    = "private"
}

# DynamoDB table to store image metadata
resource "aws_dynamodb_table" "cat_images" {
  name           = "cat-images-metadata"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "image_id"

  attribute {
    name = "image_id"
    type = "S"
  }

  attribute {
    name = "filename"
    type = "S"
  }

  attribute {
    name = "upload_timestamp"
    type = "S"
  }

  attribute {
    name = "s3_key"
    type = "S"
  }

  global_secondary_index {
    name               = "ByTimestamp"
    hash_key           = "upload_timestamp"
    projection_type    = "ALL"
    read_capacity      = 1
    write_capacity     = 1
  }
}

# Lambda function to handle API requests
resource "aws_lambda_function" "cat_handler" {
  filename         = "lambda/cat_handler.zip"
  function_name    = "cat-image-handler"
  role             = aws_iam_role.lambda_exec.arn
  handler          = "cat_handler.lambda_handler"
  runtime          = "python3.9"
  source_code_hash = filebase64sha256("lambda/cat_handler.zip")

  environment {
    variables = {
      S3_BUCKET_NAME = aws_s3_bucket.cat_images.bucket
      TABLE_NAME     = aws_dynamodb_table.cat_images.name
    }
  }
}

# IAM role for Lambda execution
resource "aws_iam_role" "lambda_exec" {
  name = "cat-lambda-exec-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_exec" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
  role       = aws_iam_role.lambda_exec.name
}

# Extra permissions for S3 and DynamoDB access
resource "aws_iam_policy" "lambda_extra" {
  name = "cat-lambda-s3-dynamodb"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "s3:PutObject",
          "s3:GetObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.cat_images.arn,
          "${aws_s3_bucket.cat_images.arn}/*"
        ]
      },
      {
        Effect = "Allow"
        Action = [
          "dynamodb:PutItem",
          "dynamodb:GetItem",
          "dynamodb:Query",
          "dynamodb:Scan"
        ]
        Resource = aws_dynamodb_table.cat_images.arn
      }
    ]
  })
}

resource "aws_iam_policy_attachment" "lambda_extra_attach" {
  name       = "cat-lambda-extra-attach"
  policy_arn = aws_iam_policy.lambda_extra.arn
  roles      = [aws_iam_role.lambda_exec.name]
}

# API Gateway REST API
resource "aws_api_gateway_rest_api" "cat_api" {
  name        = "CatImageAPI"
  description = "API for uploading and retrieving cat images"
  body = jsonencode({
    openapi = "3.0.1"
    info = {
      title   = "CatImageAPI"
      version = "1.0"
    }
    paths = {
      "/upload" = {
        post = {
          x-amazon-apigateway-integration = {
            type                    = "aws_proxy"
            httpMethod              = "POST"
            uri                     = aws_lambda_function.cat_handler.invoke_arn
            payloadFormatVersion    = "2.0"
          }
          responses = {
            default = {
              description = "Success"
            }
          }
          summary     = "Upload a cat image"
          operationId = "uploadCatImage"
        }
      }
      "/random" = {
        get = {
          x-amazon-apigateway-integration = {
            type                 = "aws_proxy"
            httpMethod           = "POST"
            uri                  = aws_lambda_function.cat_handler.invoke_arn
            payloadFormatVersion = "2.0"
          }
          responses = {
            default = {
              description = "Success"
            }
          }
          summary     = "Get a random cat image"
          operationId = "getRandomCatImage"
        }
      }
    }
  })
}

# Deploy the API
resource "aws_api_gateway_deployment" "cat_api_deploy" {
  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  stage_name  = "prod"

  triggers = {
    redeployment = sha1(jsonencode([
      aws_lambda_function.cat_handler.source_code_hash,
      aws_api_gateway_rest_api.cat_api.body,
    ]))
  }

  lifecycle {
    replace_triggered_by = [aws_lambda_function.cat_handler]
    ignore_changes       = [triggers]
  }
}

# Grant API Gateway permission to invoke Lambda
resource "aws_lambda_permission" "apigw" {
  statement_id  = "AllowExecutionFromAPIGateway"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.cat_handler.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.cat_api.execution_arn}/*/*"
}

# Random suffix for unique bucket names
resource "random_string" "suffix" {
  length  = 8
  special = false
  upper   = false
}

