variable "region" {
  default = "us-east-1"
}

# S3 bucket for storing cat images
resource "aws_s3_bucket" "cat_images" {
  bucket = "caas-cat-images"
  acl    = "private"

  versioning {
    enabled = false
  }

  lifecycle {
    prevent_destroy = true
  }
}

# DynamoDB table for cats with primary key "name"
resource "aws_dynamodb_table" "cats" {
  name           = "caas-cats"
  billing_mode   = "PAY_PER_REQUEST"
  hash_key       = "name"

  attribute {
    name = "name"
    type = "S"
  }
}

# Lambda function for handling GET requests
resource "aws_lambda_function" "caas_get_lambda" {
  filename         = "caas_get.zip"
  function_name    = "caas_get"
  role             = aws_iam_role.lambda_exec.arn
  handler          = "index.handler"
  runtime          = "python3.9"
  source_code_hash = filebase64sha256("caas_get.zip")
}

# Lambda function for handling PUT requests
resource "aws_lambda_function" "caas_put_lambda" {
  filename         = "caas_put.zip"
  function_name    = "caas_put"
  role             = aws_iam_role.lambda_exec.arn
  handler          = "index.handler"
  runtime          = "python3.9"
  source_code_hash = filebase64sha256("caas_put.zip")
}

# IAM role for Lambda execution
resource "aws_iam_role" "lambda_exec" {
  name = "caas_lambda_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      }
    ]
  })
}

# IAM policy for Lambda functions
resource "aws_iam_role_policy" "lambda_policy" {
  name = "caas_lambda_policy"
  role = aws_iam_role.lambda_exec.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "dynamodb:GetItem",
          "dynamodb:PutItem",
          "dynamodb:Scan"
        ]
        Resource = aws_dynamodb_table.cats.arn
      },
      {
        Effect = "Allow"
        Action = [
          "s3:GetObject",
          "s3:PutObject"
        ]
        Resource = "${aws_s3_bucket.cat_images.arn}/*"
      },
      {
        Effect = "Allow"
        Action = [
          "logs:CreateLogGroup",
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Resource = "arn:aws:logs:*:*:*"
      }
    ]
  })
}

# API Gateway REST API
resource "aws_api_gateway_rest_api" "caas_api" {
  name = "caas"
}

# API Gateway Resource
resource "aws_api_gateway_resource" "caas_cat" {
  rest_api_id = aws_api_gateway_rest_api.caas_api.id
  parent_id   = aws_api_gateway_rest_api.caas_api.root_resource_id
  path_part   = "cat"
}

# API Gateway Method: GET
resource "aws_api_gateway_method" "caas_get" {
  rest_api_id   = aws_api_gateway_rest_api.caas_api.id
  resource_id   = aws_api_gateway_resource.caas_cat.id
  http_method   = "GET"
  authorization = "NONE"
}

# API Gateway Integration for GET method
resource "aws_api_gateway_integration" "caas_get_integration" {
  rest_api_id             = aws_api_gateway_rest_api.caas_api.id
  resource_id             = aws_api_gateway_resource.caas_cat.id
  http_method             = aws_api_gateway_method.caas_get.http_method
  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.caas_get_lambda.invoke_arn
}

# API Gateway Method: PUT
resource "aws_api_gateway_method" "caas_put" {
  rest_api_id   = aws_api_gateway_rest_api.caas_api.id
  resource_id   = aws_api_gateway_resource.caas_cat.id
  http_method   = "PUT"
  authorization = "NONE"
}

# API Gateway Integration for PUT method
resource "aws_api_gateway_integration" "caas_put_integration" {
  rest_api_id             = aws_api_gateway_rest_api.caas_api.id
  resource_id             = aws_api_gateway_resource.caas_cat.id
  http_method             = aws_api_gateway_method.caas_put.http_method
  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.caas_put_lambda.invoke_arn
}

# Permission for API Gateway to invoke GET Lambda
resource "aws_lambda_permission" "apigateway_get_permission" {
  statement_id  = "AllowAPIGatewayInvokeGet"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.caas_get_lambda.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.caas_api.execution_arn}/*/GET/cat"
}

# Permission for API Gateway to invoke PUT Lambda
resource "aws_lambda_permission" "apigateway_put_permission" {
  statement_id  = "AllowAPIGatewayInvokePut"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.caas_put_lambda.function_name
  principal     = "apigateway.amazonaws.com"
  source_arn    = "${aws_api_gateway_rest_api.caas_api.execution_arn}/*/PUT/cat"
}

# Deploy API
resource "aws_api_gateway_deployment" "caas_deployment" {
  rest_api_id = aws_api_gateway_rest_api.caas_api.id
  stage_name  = "prod"

  triggers = {
    redeployment = sha1(jsonencode([
      aws_api_gateway_method.caas_get,
      aws_api_gateway_method.caas_put,
      aws_api_gateway_integration.caas_get_integration,
      aws_api_gateway_integration.caas_put_integration
    ]))
  }

  depends_on = [
    aws_api_gateway_method.caas_get,
    aws_api_gateway_method.caas_put,
    aws_api_gateway_integration.caas_get_integration,
    aws_api_gateway_integration.caas_put_integration
  ]
}
```

