```hcl
# Define required providers
provider "aws" {
  region = "us-west-2"
}

# Generate a key pair for EC2 instance
resource "aws_key_pair" "ec2_key_pair" {
  key_name   = "terraform-ec2-key"
  public_key = "ssh-rsa AAAAB3NzaC1yc2EAAAADAQABAAABAQC6... your-public-key-here ...== terraform" # Replace with your actual public key
}

# Create an EC2 instance
resource "aws_instance" "web_server" {
  ami           = "ami-0c02fb55956c7d316" # Example: Amazon Linux 2 in us-west-2
  instance_type = "t3.micro"
  key_name      = aws_key_pair.ec2_key_pair.key_name

  tags = {
    Name = "backup-enabled-instance"
    Backup = "daily"
  }
}

# Create a Backup Vault
resource "aws_backup_vault" "backup_vault" {
  name = "daily-backup-vault"
}

# Define a Backup Plan
resource "aws_backup_plan" "daily_backup_plan" {
  name = "daily-12am-backup-plan"

  rule {
    rule_name         = "daily-12am-rule"
    target_vault_name = aws_backup_vault.backup_vault.name
    schedule          = "cron(0 0 * * ? *)"  # Daily at 12:00 AM UTC
    start_window      = 60 # minutes
    completion_window = 120 # minutes

    lifecycle {
      delete_after = 35 # Keep backups for 35 days
    }
  }

  advanced_backup_setting {
    backup_options = {
      WindowsVSS = "enabled"
    }
    resource_type = "EC2"
  }
}

# Assign Backup Plan to EC2 Instance via Backup Selection
resource "aws_backup_selection" "backup_selection" {
  iam_role_arn = aws_iam_role.backup_role.arn
  name         = "ec2-backup-selection"
  plan_id      = aws_backup_plan.daily_backup_plan.id

  selection_tag {
    type  = "STRINGEQUALS"
    key   = "Backup"
    value = "daily"
  }
}

# IAM Role required for AWS Backup
resource "aws_iam_role" "backup_role" {
  name = "aws-backup-service-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      }
    ]
  })
}

# Attach required policy to IAM role
resource "aws_iam_role_policy_attachment" "backup_policy_attachment" {
  role       = aws_iam_role.backup_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
}

# Optionally, add EC2 full access to ensure backups can be performed
resource "aws_iam_role_policy_attachment" "backup_ec2_attachment" {
  role       = aws_iam_role.backup_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonEC2FullAccess"
}
```

