extracted_code:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 4.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Origin resources can be placed in any region
}

# S3 bucket to store video content
resource "aws_s3_bucket" "video_content" {
  bucket = "my-global-video-streaming-bucket"

  # Enable versioning for data durability
  versioning {
    enabled = true
  }

  # Block public access (CloudFront will access via origin access control)
  block_public_acls        = true
  block_public_policy      = true
  ignore_public_acls       = true
  restrict_public_buckets  = true

  # Enable server-side encryption
  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  # Lifecycle rule to manage older versions (optional cost-saving)
  lifecycle_rule {
    enabled = true
    id      = "delete-old-versions"
    noncurrent_version_expiration {
      days = 30
    }
  }
}

# Ensure bucket policy allows CloudFront to access the content
resource "aws_s3_bucket_policy" "cloudfront_access" {
  bucket = aws_s3_bucket.video_content.id
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Sid = "AllowCloudFrontServicePrincipalReadOnly",
        Effect = "Allow",
        Principal = {
          Service = "cloudfront.amazonaws.com"
        },
        Action = [
          "s3:GetObject"
        ],
        Resource = "${aws_s3_bucket.video_content.arn}/*",
        Condition = {
          StringEquals = {
            "AWS:SourceArn" = "arn:aws:cloudfront::${data.aws_caller_identity.current.account_id}:distribution/${aws_cloudfront_distribution.video_distribution.id}"
          }
        }
      }
    ]
  })
}

# Origin Access Control to securely connect CloudFront to S3
resource "aws_cloudfront_origin_access_control" "s3_oac" {
  name                              = "s3-oac-video-streaming"
  description                       = "Origin Access Control for S3 video content"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

# CloudFront distribution for global content delivery
resource "aws_cloudfront_distribution" "video_distribution" {
  origin {
    domain_name = aws_s3_bucket.video_content.bucket_regional_domain_name
    origin_id   = "S3-video-origin"

    # Use the Origin Access Control
    origin_access_control_id = aws_cloudfront_origin_access_control.s3_oac.id
  }

  enabled             = true
  is_ipv6_enabled     = true
  comment             = "Global video streaming distribution"
  default_root_object = "index.html"

  # Use a price class to balance cost and coverage (e.g., all Edge Locations)
  price_class = "PriceClass_All"

  # Default cache behavior
  default_cache_behavior {
    target_origin_id       = "S3-video-origin"
    viewer_protocol_policy = "redirect-to-https"
    allowed_methods        = ["GET", "HEAD", "OPTIONS"]
    cached_methods         = ["GET", "HEAD"]

    # Use managed cache policy for HTTP methods
    cache_policy_id      = "658327ea-f89d-4fab-a63d-7e88639e58f6" # Managed-CachingOptimized
    origin_request_policy_id = "88a5eaf4-2fd4-4709-b370-b4c650ea3fcf" # Managed-CORS-S3Origin
    response_headers_policy_id = "67f7725c-6f97-4210-82d7-5512b31e9d03" # Managed-SimpleCORS
  }

  # Cache policy configured for video streaming files (e.g., .mp4, .m3u8)
  ordered_cache_behavior {
    path_pattern     = "*.mp4"
    target_origin_id = "S3-video-origin"
    viewer_protocol_policy = "redirect-to-https"
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]

    cache_policy_id = "4135ea2d-6df8-44a3-9df3-4b5a84be39ad" # Managed-CachingOptimizedForStreaming
  }

  # Add support for HLS/DASH manifest files
  ordered_cache_behavior {
    path_pattern     = "*.m3u8"
    target_origin_id = "S3-video-origin"
    viewer_protocol_policy = "redirect-to-https"
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
