terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# S3 bucket for static content (videos, thumbnails, etc.)
resource "aws_s3_bucket" "video_content" {
  bucket = "video-streaming-platform-content"

  acl = "private"

  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  tags = {
    Name        = "Video Streaming Content Bucket"
    Environment = "production"
  }
}

# CloudFront origin access identity to securely connect CloudFront to S3
resource "aws_cloudfront_origin_access_identity" "oai" {
  comment = "OAI for video streaming S3 bucket"
}

# CloudFront distribution for global content delivery
resource "aws_cloudfront_distribution" "video_distribution" {
  origin {
    domain_name = aws_s3_bucket.video_content.bucket_regional_domain_name
    origin_id   = "S3-${aws_s3_bucket.video_content.id}"

    s3_origin_config {
      origin_access_identity = aws_cloudfront_origin_access_identity.oai.cloudfront_access_identity_path
    }
  }

  enabled             = true
  is_ipv6_enabled     = true
  comment             = "Global video streaming distribution"
  default_root_object = "index.html"

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-${aws_s3_bucket.video_content.id}"

    forward_cookies {
      forward = "none"
    }

    forward_query_string = false

    min_ttl     = 0
    default_ttl = 86400
    max_ttl     = 31536000

    compress = true

    viewer_protocol_policy = "redirect-to-https"
  }

  # Cache policy for static assets
  ordered_cache_behavior {
    path_pattern     = "/static/*"
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-${aws_s3_bucket.video_content.id}"

    min_ttl     = 0
    default_ttl = 604800
    max_ttl     = 31536000

    forward_cookies {
      forward = "none"
    }

    forward_query_string = false

    compress = true

    viewer_protocol_policy = "redirect-to-https"
  }

  # Restrict to HTTPS
  viewer_certificate {
    cloudfront_default_certificate = true
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  price_class = "PriceClass_200" # Balance between performance and cost
}

# Route 53 hosted zone for custom domain
resource "aws_route53_zone" "main" {
  name = "videostream.example.com"

  tags = {
    Environment = "production"
    Project     = "VideoStreamingPlatform"
  }
}

# DNS record pointing to CloudFront distribution
resource "aws_route53_record" "cdn" {
  zone_id = aws_route53_zone.main.zone_id
  name    = "cdn.videostream.example.com"
  type    = "A"

  alias {
    name                   = aws_cloudfront_distribution.video_distribution.domain_name
    zone_id                = aws_cloudfront_distribution.video_distribution.hosted_zone_id
    evaluate_target_health = false
  }
}

# Health check for failover or monitoring
resource "aws_route53_health_check" "video_health" {
  fqdn              = aws_cloudfront_distribution.video_distribution.domain_name
  port              = 443
  type              = "HTTPS"
  resource_path     = "/"
  failure_threshold = "3"
  request_interval  = "30"

  tags = {
    Name = "CloudFront Health Check"
  }
}

# Log bucket for CloudFront access logs
resource "aws_s3_bucket" "cloudfront_logs" {
  bucket = "video-streaming-cloudfront-logs"

  acl = "log-delivery-write"

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }

  tags = {
    Name        = "CloudFront Access Logs"
    Environment = "production"
  }
}

# Update CloudFront to enable access logging
resource "aws_cloudfront_distribution" "video_distribution_with_logging" {
  # Copy all settings from aws_cloudfront_distribution.video_distribution but add logging
  # Workaround: Interpolate the existing distribution with added logging
  lifecycle {
    replace_triggered_by = [aws_cloudfront_distribution.video_distribution]
    ignore_changes       = []
  }

  # Most attributes are copied implicitly via for_each or dynamic, but we recreate with logging
  # Simulate update by referencing original configuration with added log settings
  # (In practice, you’d use a module or data-driven approach, but here we simplify.)

  # Reuse the same configuration as above, but add logging block
  # (We're redefining it here to include logs – in production, use a module)

  # For brevity and clarity, showing full redefinition with logs:
  origin {
    domain_name = aws_s3_bucket.video_content.bucket_regional_domain_name
    origin_id   = "S3-${aws_s3_bucket.video_content.id}"

    s3_origin_config {
      origin_access_identity = aws_cloudfront_origin_access_identity.oai.cloudfront_access_identity_path
    }
  }

  enabled             = true
  is_ipv6_enabled     = true
  comment             = "Global video streaming distribution with logging"
  default_root_object = "index.html"

  logging_config {
    include_cookies = false
    bucket          = aws_s3_bucket.cloudfront_logs.bucket_regional_domain_name
    prefix          = "logs/"
  }

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-${aws_s3_bucket.video_content.id}"

    forward_cookies {
      forward = "none"
    }

    forward_query_string = false

    min_ttl     = 0
    default_ttl = 86400
    max_ttl     = 31536000

    compress = true

    viewer_protocol_policy = "redirect-to-https"
  }

  ordered_cache_behavior {
    path_pattern     = "/static/*"
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-${aws_s3_bucket.video_content.id}"

    min_ttl     = 0
    default_ttl = 604800
    max_ttl     = 31536000

    forward_cookies {
      forward = "none"
    }

    forward_query_string = false

    compress = true

    viewer_protocol_policy = "redirect-to-https"
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  price_class = "PriceClass_200"
}

# Output the CloudFront domain name
output "cloudfront_domain" {
  value = aws_cloudfront_distribution.video_distribution_with_logging.domain_name
}

# Output the S3 bucket name
output "content_bucket_name" {
  value = aws_s3_bucket.video_content.bucket
}

# Output the Route 53 zone
output "hosted_zone_id" {
  value = aws_route53_zone.main.zone_id
}

