      origin_access_identity = aws_cloudfront_origin_access_identity.oai.cloudfront_access_identity_path
    }
  }

  enabled             = true
  is_ipv6_enabled     = true
  comment             = "Global video streaming distribution with logging"
  default_root_object = "index.html"

  logging_config {
    include_cookies = false
    bucket          = aws_s3_bucket.cloudfront_logs.bucket_regional_domain_name
    prefix          = "logs/"
  }

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-${aws_s3_bucket.video_content.id}"

    forward_cookies {
      forward = "none"
    }

    forward_query_string = false

    min_ttl     = 0
    default_ttl = 86400
    max_ttl     = 31536000

    compress = true

    viewer_protocol_policy = "redirect-to-https"
  }

  ordered_cache_behavior {
    path_pattern     = "/static/*"
    allowed_methods  = ["GET", "HEAD", "OPTIONS"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "S3-${aws_s3_bucket.video_content.id}"

    min_ttl     = 0
    default_ttl = 604800
    max_ttl     = 31536000

    forward_cookies {
      forward = "none"
    }

    forward_query_string = false

    compress = true

    viewer_protocol_policy = "redirect-to-https"
  }

  viewer_certificate {
    cloudfront_default_certificate = true
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  price_class = "PriceClass_200"
}

# Output the CloudFront domain name
output "cloudfront_domain" {
  value = aws_cloudfront_distribution.video_distribution_with_logging.domain_name
}

# Output the S3 bucket name
output "content_bucket_name" {
  value = aws_s3_bucket.video_content.bucket
}

# Output the Route 53 zone
output "hosted_zone_id" {
  value = aws_route53_zone.main.zone_id
}
