```hcl
locals {
  project_name = "video-streaming-platform"
  vpc_cidr   = "10.0.0.0/16"
  env        = "prod"
}

provider "aws" {
  region = "us-east-1"
}

# VPC Module
module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "5.10.0"

  name = "${local.project_name}-vpc"
  cidr = local.vpc_cidr

  azs             = ["us-east-1a", "us-east-1b"]
  private_subnets = ["10.0.1.0/24", "10.0.2.0/24"]
  public_subnets  = ["10.0.101.0/24", "10.0.102.0/24"]

  enable_nat_gateway = true
  single_nat_gateway = true

  enable_dns_hostnames = true
  enable_dns_support   = true

  public_subnet_tags = {
    "kubernetes.io/role/elb" = "1"
  }

  private_subnet_tags = {
    "kubernetes.io/role/internal-elb" = "1"
  }
}

# EC2 Instances for Video Streaming Servers
resource "aws_instance" "streaming_servers" {
  count                       = 3
  ami                         = "ami-0c02fb55956c7d316" # Amazon Linux 2 in us-east-1
  instance_type               = "t3.large"
  key_name                    = "my-key-pair"
  subnet_id                   = element(module.vpc.private_subnets, count.index % length(module.vpc.private_subnets))
  vpc_security_group_ids      = [aws_security_group.streaming_sg.id]

  user_data = <<-EOF
              #!/bin/bash
              sudo yum update -y
              sudo amazon-linux-extras install nginx1 -y
              sudo systemctl start nginx
              sudo systemctl enable nginx
              echo "<h1>Video Streaming Server ${count.index + 1}</h1>" > /usr/share/nginx/html/index.html
              EOF

  tags = {
    Name = "${local.project_name}-server-${count.index + 1}"
  }
}

# Security Group for EC2 Instances
resource "aws_security_group" "streaming_sg" {
  name        = "${local.project_name}-streaming-sg"
  description = "Security group for video streaming servers"
  vpc_id      = module.vpc.vpc_id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Application Load Balancer
resource "aws_lb" "streaming_alb" {
  name               = "${local.project_name}-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = module.vpc.public_subnets

  tags = {
    Name = "${local.project_name}-alb"
  }
}

# ALB Security Group
resource "aws_security_group" "alb_sg" {
  name        = "${local.project_name}-alb-sg"
  description = "Security group for ALB"
  vpc_id      = module.vpc.vpc_id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# ALB Target Group
resource "aws_lb_target_group" "streaming_tg" {
  name     = "${local.project_name}-tg"
  port     = 80
  protocol = "HTTP"
  vpc_id   = module.vpc.vpc_id

  health_check {
    path                = "/"
    protocol            = "HTTP"
    port                = "traffic-port"
    healthy_threshold   = 3
    unhealthy_threshold = 3
    timeout             = 30
    interval            = 30
  }
}

# ALB Listener
resource "aws_lb_listener" "streaming_listener" {
  load_balancer_arn = aws_lb.streaming_alb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.streaming_tg.arn
  }
}

# Register EC2 instances with Target Group
resource "aws_lb_target_group_attachment" "streaming_attachments" {
  count            = length(aws_instance.streaming_servers)
  target_group_arn = aws_lb_target_group.streaming_tg.arn
  target_id        = aws_instance.streaming_servers[count.index].id
  port             = 80
}

# Route 53 Hosted Zone
resource "aws_route53_zone" "primary" {
  name = "videostream.example.com"
}

# Route 53 Record pointing to ALB
resource "aws_route53_record" "www" {
  zone_id = aws_route53_zone.primary.zone_id
  name    = "www.videostream.example.com"
  type    = "A"

  alias {
    name                   = aws_lb.streaming_alb.dns_name
    zone_id                = aws_lb.streaming_alb.zone_id
    evaluate_target_health = true
  }
}

# CloudFront Distribution for Video Caching and Delivery
resource "aws_cloudfront_distribution" "streaming_distribution" {
  origin {
    domain_name = aws_lb.streaming_alb.dns_name
    origin_id   = "${local.project_name}-alb-origin"

    custom_origin_config {
      http_port              = 80
      https_port             = 443
      origin_protocol_policy = "http-only"
      origin_ssl_protocols   = ["TLSv1.2"]
    }
  }

  enabled             = true
  comment             = "CloudFront for video streaming"
  default_root_object = "index.html"

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = "${local.project_name}-alb-origin"

    forwarded_values {
      query_string = false
      cookies {
        forward = "none"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    min_ttl                = 0
    default_ttl            = 3600
    max_ttl                = 86400
  }

  price_class = "PriceClass_All"

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  tags = {
    Environment = "production"
    Project     = local.project_name
  }
}

# Optional: S3 Bucket for Storing Videos
resource "aws_s3_bucket" "video_storage" {
  bucket = "${local.project_name}-video-storage-${format("%x", random_id.bucket_suffix.hex)}"
  tags   = {
    Name = "Video Storage Bucket"
  }
}

resource "aws_s3_bucket_versioning" "video_storage_versioning" {
  bucket = aws_s3_bucket.video_storage.id
  versioning_configuration {
    status = "Enabled"
  }
}

# Generate random suffix for unique S3 bucket name
resource "random_id" "bucket_suffix" {
  byte_length = 8
}

# Output ALB DNS Name
output "alb_dns_name" {
  value = aws_lb.streaming_alb.dns_name
}

# Output CloudFront Domain
output "cloudfront_domain" {
  value = aws_cloudfront_distribution.streaming_distribution.domain_name
}

# Output Route 53 Zone
output "hosted_zone_id" {
  value = aws_route53_zone.primary.zone_id
}
```

