```hcl
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

# VPC Module (using the terraform-aws-modules/vpc/aws)
module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "~> 5.0"

  name = "video-streaming-vpc"
  cidr = "10.0.0.0/16"

  azs             = ["us-east-1a", "us-east-1b", "us-east-1c"]
  public_subnets  = ["10.0.1.0/24", "10.0.2.0/24", "10.0.3.0/24"]
  private_subnets = ["10.0.101.0/24", "10.0.102.0/24", "10.0.103.0/24"]

  enable_nat_gateway = true
  single_nat_gateway = true
  enable_dns_hostnames = true

  public_subnet_tags = {
    Name = "video-streaming-public"
  }

  private_subnet_tags = {
    Name = "video-streaming-private"
  }
}

# Security Group for EC2 Instances
resource "aws_security_group" "streaming_sg" {
  name        = "streaming-servers-sg"
  description = "Security group for video streaming EC2 instances"
  vpc_id      = module.vpc.vpc_id

  # Allow HTTP (80) and HTTPS (443) from Load Balancer
  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow SSH (22) from anywhere (restrict in production)
  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  # Allow all outbound traffic
  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "streaming-servers-sg"
  }
}

# EC2 Instance Role (with S3 and CloudWatch access if needed)
resource "aws_iam_role" "ec2_role" {
  name = "video-streaming-ec2-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_instance_profile" "ec2_profile" {
  name = "video-streaming-ec2-profile"
  role = aws_iam_role.ec2_role.name
}

# User data script for EC2 instances
resource "aws_ami_from_instance" "dummy" {
  count         = 0 # Just to provide valid data source; will not create real AMI
  name          = "dummy"
  source_instance_id = "i-0123456789"
  lifecycle {
    ignore_changes = all
  }
}

locals {
  user_data = base64encode(<<-EOF
              #!/bin/bash
              sudo apt-get update -y
              sudo apt-get install -y nginx
              sudo systemctl start nginx
              sudo systemctl enable nginx
              echo '<h1>Streaming Server Ready</h1>' > /var/www/html/index.html
              EOF
  )
}

# EC2 Instances (Streaming servers)
resource "aws_instance" "streaming_server" {
  count                       = 3
  ami                         = "ami-0c02fb55956c7d316" # Amazon Linux 2 in us-east-1
  instance_type               = "t3.medium"
  subnet_id                   = module.vpc.public_subnets[count.index % length(module.vpc.public_subnets)]
  vpc_security_group_ids      = [aws_security_group.streaming_sg.id]
  iam_instance_profile        = aws_iam_instance_profile.ec2_profile.name
  user_data                   = local.user_data
  associate_public_ip_address = true
  tags = {
    Name = "streaming-server-${count.index}"
  }
}

# Target Group for Load Balancer
resource "aws_lb_target_group" "streaming_tg" {
  name     = "streaming-target-group"
  port     = 80
  protocol = "HTTP"
  vpc_id   = module.vpc.vpc_id

  health_check {
    path                = "/health"
    interval            = 30
    timeout             = 5
    healthy_threshold   = 2
    unhealthy_threshold = 2
    matcher             = "200"
  }

  tags = {
    Name = "streaming-target-group"
  }
}

# Attach EC2 instances to Target Group
resource "aws_lb_target_group_attachment" "streaming_tg_attachment" {
  count            = length(aws_instance.streaming_server)
  target_group_arn = aws_lb_target_group.streaming_tg.arn
  target_id        = aws_instance.streaming_server[count.index].id
  port             = 80
}

# Application Load Balancer
resource "aws_lb" "streaming_alb" {
  name               = "streaming-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.streaming_sg.id]
  subnets            = module.vpc.public_subnets

  enable_deletion_protection = false

  tags = {
    Name = "streaming-alb"
  }
}

# ALB Listener
resource "aws_lb_listener" "http_listener" {
  load_balancer_arn = aws_lb.streaming_alb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.streaming_tg.arn
  }
}

# Route53 Hosted Zone
resource "aws_route53_zone" "streaming_zone" {
  name = "videostreaming.example.com"
  tags = {
    Environment = "production"
  }
}

# DNS Record for Load Balancer
resource "aws_route53_record" "www" {
  zone_id = aws_route53_zone.streaming_zone.zone_id
  name    = "www.videostreaming.example.com"
  type    = "A"

  alias {
    name                   = aws_lb.streaming_alb.dns_name
    zone_id                = aws_lb.streaming_alb.zone_id
    evaluate_target_health = true
  }
}

# Additional Security Group for ALB
resource "aws_security_group" "alb_sg" {
  name        = "alb-security-group"
  description = "Security group for ALB"
  vpc_id      = module.vpc.vpc_id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "alb-sg"
  }
}

# Update ALB to use ALB security group
resource "aws_lb" "streaming_alb" {
  name               = "streaming-alb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.alb_sg.id]
  subnets            = module.vpc.public_subnets

  enable_deletion_protection = false

  tags = {
    Name = "streaming-alb"
  }
}
```

