variable "vpc_id" {
  description = "ID of the existing VPC where RDS will be deployed"
  type        = string
}

variable "private_subnet_ids" {
  description = "List of private subnet IDs for the RDS instance"
  type        = list(string)
}

variable "db_instance_class" {
  description = "Instance class for the RDS instance"
  type        = string
  default     = "db.t4g.medium"
}

variable "db_name" {
  description = "Name of the initial database"
  type        = string
  default     = "mydb"
}

variable "db_username" {
  description = "Master username for the database"
  type        = string
  default     = "admin"
}

variable "db_password" {
  description = "Master password for the database"
  type        = string
  sensitive   = true
}

variable "engine_version" {
  description = "PostgreSQL engine version"
  type        = string
  default     = "15.4"
}

variable "allocated_storage" {
  description = "Allocated storage in GB"
  type        = number
  default     = 100
}

variable "kms_key_arn" {
  description = "ARN of the customer-managed KMS key for encryption"
  type        = string
}

resource "aws_kms_key" "rds_kms_key" {
  count         = var.kms_key_arn == "" ? 1 : 0
  description   = "KMS key for RDS PostgreSQL encryption"
  enable_key_rotation = true
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = { AWS = "arn:aws:iam::${data.aws_caller_identity.current.account_id}:root" }
        Action = [
          "kms:Create*",
          "kms:Describe*",
          "kms:Enable*",
          "kms:List*",
          "kms:Put*",
          "kms:Update*",
          "kms:Revoke*",
          "kms:Disable*",
          "kms:Get*",
          "kms:Decrypt",
          "kms:Encrypt",
          "kms:ReEncrypt*",
          "kms:GenerateDataKey*",
          "kms:Describe*"
        ]
        Resource = "*"
      }
    ]
  })
}

data "aws_caller_identity" "current" {}

resource "aws_security_group" "rds_sg" {
  name        = "rds-postgresql-sg"
  description = "Allow PostgreSQL access from application servers"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/8"]  # Adjust to your application's CIDR
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "RDS-PostgreSQL-SecurityGroup"
  }
}

resource "aws_db_parameter_group" "postgres_param_group" {
  name        = "custom-postgres-15"
  family      = "postgres15"
  description = "Custom PostgreSQL parameter group"

  parameter {
    name  = "log_statement"
    value = "all"
  }

  parameter {
    name  = "rds.log_retention_period"
    value = "1440"
  }

  tags = {
    Environment = "production"
  }
}

resource "aws_db_subnet_group" "rds_subnet_group" {
  name       = "rds-subnet-group"
  subnet_ids = var.private_subnet_ids

  tags = {
    Name = "RDS-Subnet-Group"
  }
}

resource "aws_db_instance" "postgres_instance" {
  identifier                        = "protected-postgres-instance"
  engine                            = "postgres"
  engine_version                    = var.engine_version
  instance_class                    = var.db_instance_class
  allocated_storage                 = var.allocated_storage
  max_allocated_storage             = 200
  db_name                           = var.db_name
  username                          = var.db_username
  password                          = var.db_password
  db_subnet_group_name              = aws_db_subnet_group.rds_subnet_group.name
  vpc_security_group_ids            = [aws_security_group.rds_sg.id]
  parameter_group_name              = aws_db_parameter_group.postgres_param_group.name
  multi_az                          = true
  storage_encrypted                 = true
  kms_key_id                        = var.kms_key_arn != "" ? var.kms_key_arn : aws_kms_key.rds_kms_key[0].arn
  skip_final_snapshot               = true
  backup_retention_period           = 7
  deletion_protection               = true
  enabled_cloudwatch_logs_exports   = ["postgresql"]
  publicly_accessible               = false
  apply_immediately                 = false
  auto_minor_version_upgrade        = true
  maintenance_window                = "sun:05:00-sun:07:00"
  backup_window                     = "03:00-05:00"

  tags = {
    Name        = "Protected-PostgreSQL-RDS"
    Environment = "production"
  }
}

