    name  = "log_min_duration_statement"
    value = "5000"
  }

  parameter {
    name  = "max_connections"
    value = "300"
  }
}

resource "aws_kms_key" "db_encryption_key" {
  description             = "KMS key for encrypting the RDS instance"
  deletion_window_in_days = 10
  enable_key_rotation     = true
}

resource "aws_security_group" "rds_security_group" {
  name        = "rds-secure-access"
  description = "Security group for PostgreSQL RDS instance"
  vpc_id      = aws_vpc.main.id

  # Allow PostgreSQL access only from private subnets
  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["10.0.1.0/24", "10.0.2.0/24"]  # Example private subnet CIDRs
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "RDS-Security-Group"
  }
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "Main-VPC"
  }
}

resource "aws_subnet" "private_subnet_1" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-west-2a"
  map_public_ip_on_launch = false

  tags = {
    Name = "Private-Subnet-1"
  }
}

resource "aws_subnet" "private_subnet_2" {
  vpc_id                  = aws_vpc.main.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-west-2b"
  map_public_ip_on_launch = false

  tags = {
    Name = "Private-Subnet-2"
  }
}

resource "aws_db_subnet_group" "private_db_subnet_group" {
  name       = "private-db-subnet-group"
  subnet_ids = [aws_subnet.private_subnet_1.id, aws_subnet.private_subnet_2.id]

  tags = {
    Name = "Private-DB-Subnet-Group"
  }
}

resource "aws_db_instance" "postgres_rds" {
  identifier                  = "protected-postgres-instance"
  engine                      = "postgres"
  engine_version              = "14.7"
  instance_class              = "db.t3.medium"
  allocated_storage           = 100
  storage_type                = "gp2"
  db_name                     = "mydb"
  username                    = "dbadmin"
  password                    = "securepassword123"
  publicly_accessible         = false
  skip_final_snapshot         = false
  final_snapshot_identifier   = "pgsnapshot"
  multi_az                    = true
  backup_retention_period     = 7
  vpc_security_group_ids      = [aws_security_group.rds_security_group.id]
  db_subnet_group_name        = aws_db_subnet_group.private_db_subnet_group.name
  parameter_group_name        = aws_db_parameter_group.postgres_custom.name
  storage_encrypted           = true
  kms_key_id                  = aws_kms_key.db_encryption_key.arn
  apply_immediately           = false
  auto_minor_version_upgrade  = true
  maintenance_window          = "sun:05:00-sun:07:00"
  backup_window               = "03:00-05:00"

  tags = {
    Name = "Protected-PostgreSQL-RDS"
  }
}
```

