```hcl
provider "aws" {
  region = "us-west-2"
}

# VPC for the Aurora DB and RDS Proxy
resource "aws_vpc" "aurora_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "aurora-vpc"
  }
}

# Subnets for high availability (spread across multiple AZs)
resource "aws_subnet" "aurora_subnet_az1" {
  vpc_id                  = aws_vpc.aurora_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = "us-west-2a"
  map_public_ip_on_launch = false

  tags = {
    Name = "aurora-subnet-az1"
  }
}

resource "aws_subnet" "aurora_subnet_az2" {
  vpc_id                  = aws_vpc.aurora_vpc.id
  cidr_block              = "10.0.2.0/24"
  availability_zone       = "us-west-2b"
  map_public_ip_on_launch = false

  tags = {
    Name = "aurora-subnet-az2"
  }
}

# Subnet group for Aurora
resource "aws_db_subnet_group" "aurora_subnet_group" {
  name       = "aurora-subnet-group"
  subnet_ids = [aws_subnet.aurora_subnet_az1.id, aws_subnet.aurora_subnet_az2.id]

  tags = {
    Name = "aurora-subnet-group"
  }
}

# Security group for Aurora DB
resource "aws_security_group" "aurora_db_sg" {
  name        = "aurora-db-sg"
  description = "Allow MySQL inbound from RDS Proxy and app"
  vpc_id      = aws_vpc.aurora_vpc.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-db-security-group"
  }
}

# Security group for RDS Proxy
resource "aws_security_group" "rds_proxy_sg" {
  name        = "rds-proxy-sg"
  description = "Allow inbound from application to RDS Proxy"
  vpc_id      = aws_vpc.aurora_vpc.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-proxy-security-group"
  }
}

# IAM role for RDS Proxy to access Secrets Manager
resource "aws_iam_role" "rds_proxy_role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "rds_proxy_secrets_attach" {
  role       = aws_iam_role.rds_proxy_role.name
  policy_arn = "arn:aws:iam::aws:policy/SecretsManagerReadWrite"
}

# Database credentials stored in AWS Secrets Manager
resource "aws_secretsmanager_secret" "db_credentials" {
  name = "aurora-db-credentials"
}

resource "aws_secretsmanager_secret_version" "db_credentials_version" {
  secret_id = aws_secretsmanager_secret.db_credentials.id
  secret_string = jsonencode({
    username = "admin"
    password = random_password.db_password.result
  })
}

# Random password for DB user
resource "random_password" "db_password" {
  length  = 16
  special = true
  override_special = "!#%"
}

# Aurora MySQL cluster
resource "aws_rds_cluster" "aurora_cluster" {
  cluster_identifier              = "aurora-mysql-cluster"
  engine                          = "aurora-mysql"
  engine_version                  = "5.7.mysql_aurora.2.10.2"
  master_username                 = "admin"
  master_password                 = random_password.db_password.result
  db_subnet_group_name            = aws_db_subnet_group.aurora_subnet_group.name
  vpc_security_group_ids          = [aws_security_group.aurora_db_sg.id]
  backup_retention_period         = 7
  preferred_backup_window         = "03:00-04:00"
  skip_final_snapshot             = true
  apply_immediately               = true
  storage_encrypted               = true
  enabled_cloudwatch_logs_exports = ["error", "general", "slowquery"]
}

resource "aws_rds_cluster_instance" "aurora_instance_1" {
  count               = 2
  identifier          = "aurora-instance-${count.index}"
  cluster_identifier  = aws_rds_cluster.aurora_cluster.id
  instance_class      = "db.r5.large"
  engine              = "aurora-mysql"
  db_subnet_group_name = aws_db_subnet_group.aurora_subnet_group.name
  promotion_tier      = 1
  auto_minor_version_upgrade = true
  apply_immediately   = true
}

# RDS Proxy
resource "aws_db_proxy" "rds_proxy" {
  name                   = "aurora-proxy"
  engine_family          = "MYSQL"
  vpc_subnet_ids         = [aws_subnet.aurora_subnet_az1.id, aws_subnet.aurora_subnet_az2.id]
  vpc_security_group_ids = [aws_security_group.rds_proxy_sg.id]
  auth {
    description                    = "Authenticate with Secrets Manager"
    auth_scheme                   = "SECRETS"
    iam_auth                       = "DISABLED"
    secret_arn                     = aws_secretsmanager_secret.db_credentials.arn
  }
  role_arn                           = aws_iam_role.rds_proxy_role.arn
  require_tls                        = true
  idle_client_timeout                = 1800
  debug_logging                      = false
  max_connections_percent            = 100
  max_idle_connections_percent       = 50
  connection_pool_config {
    max_connections_percent       = 100
    max_idle_connections_percent  = 50
    connection_borrow_timeout     = 120
    session_pinning_filters       = []
    init_query                      = "SET time_zone = '+00:00'"
  }
  tags = {
    Environment = "production"
  }
}

# Associate RDS Proxy with the Aurora cluster
resource "aws_db_proxy_default_target_group" "proxy_default_target_group" {
  db_proxy_name = aws_db_proxy.rds_proxy.name

  connection_pool_config {
    max_connections_percent       = 100
    max_idle_connections_percent  = 50
    connection_borrow_timeout     = 120
    session_pinning_filters       = []
    init_query                      = "SET time_zone = '+00:00'"
  }
}

resource "aws_db_proxy_target" "proxy_target" {
  db_proxy_name = aws_db_proxy.rds_proxy.name
  target_group_name = aws_db_proxy_default_target_group.proxy_default_target_group.name
  db_instance_identifier = aws_rds_cluster_instance.aurora_instance_1[0].identifier
}
