```hcl
# Create a VPC
resource "aws_vpc" "main" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "aurora-vpc"
  }
}

# Create subnets
resource "aws_subnet" "subnet_az1" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"

  tags = {
    Name = "aurora-subnet-az1"
  }
}

resource "aws_subnet" "subnet_az2" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-west-2b"

  tags = {
    Name = "aurora-subnet-az2"
  }
}

# Create DB subnet group
resource "aws_db_subnet_group" "aurora_subnet_group" {
  name       = "aurora-subnet-group"
  subnet_ids = [aws_subnet.subnet_az1.id, aws_subnet.subnet_az2.id]

  tags = {
    Name = "aurora-subnet-group"
  }
}

# Security Group for RDS
resource "aws_security_group" "aurora_sg" {
  name        = "aurora-db-sg"
  description = "Allow MySQL/Aurora access"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "aurora-db-sg"
  }
}

# Security Group for RDS Proxy
resource "aws_security_group" "rds_proxy_sg" {
  name        = "rds-proxy-sg"
  description = "Allow RDS Proxy access"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    security_groups = [aws_security_group.app_sg.id]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-proxy-sg"
  }
}

# Security Group for application (to access proxy)
resource "aws_security_group" "app_sg" {
  name        = "app-sg"
  description = "Allow app access to RDS Proxy"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/16"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "app-sg"
  }
}

# IAM role for RDS Proxy
resource "aws_iam_role" "rds_proxy_role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

# Attach required policy to the IAM role
resource "aws_iam_role_policy_attachment" "rds_proxy_policy" {
  role       = aws_iam_role.rds_proxy_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonRDSPowerUser"
}

# Secrets Manager for DB credentials
resource "aws_secretsmanager_secret" "db_secret" {
  name = "aurora-db-credentials"
}

resource "aws_secretsmanager_secret_version" "db_secret_version" {
  secret_id     = aws_secretsmanager_secret.db_secret.id
  secret_string = jsonencode({
    username = "admin"
    password = random_password.db_password.result
  })
}

# Random password for DB
resource "random_password" "db_password" {
  length  = 16
  special = true
  override_special = "_%@"
}

# Aurora MySQL Cluster
resource "aws_rds_cluster" "aurora_cluster" {
  cluster_identifier           = "aurora-mysql-cluster"
  engine                       = "aurora-mysql"
  engine_version               = "5.7.mysql_aurora.2.10.1"
  database_name                = "mydb"
  master_username              = aws_secretsmanager_secret_version.db_secret_version.secret_string_json.username
  master_password              = aws_secretsmanager_secret_version.db_secret_version.secret_string_json.password
  db_cluster_parameter_group_name = "default.aurora-mysql5.7"
  skip_final_snapshot          = false
  final_snapshot_identifier    = "snapshot"
  db_subnet_group_name         = aws_db_subnet_group.aurora_subnet_group.name
  vpc_security_group_ids       = [aws_security_group.aurora_sg.id]
  storage_encrypted            = true
  enabled_cloudwatch_logs_exports = ["audit", "error", "general", "slowquery"]
}

# Aurora Cluster Instance
resource "aws_rds_cluster_instance" "cluster_instances" {
  count               = 1
  identifier          = "aurora-instance-${count.index}"
  cluster_identifier  = aws_rds_cluster.aurora_cluster.id
  instance_class      = "db.r5.large"
  engine              = "aurora-mysql"
  db_subnet_group_name = aws_db_subnet_group.aurora_subnet_group.name
  publicly_accessible = false
}

# RDS Proxy
resource "aws_db_proxy" "rds_proxy" {
  name                   = "aurora-rds-proxy"
  db_proxy_target_group  = aws_db_proxy_default_target_group.default.name
  engine_family          = "MYSQL"
  auth {
    description = "Authenticate with Secrets Manager"
    auth_scheme = "SECRETS"
    iam_auth    = "DISABLED"
    secret_arn  = aws_secretsmanager_secret.db_secret.arn
  }
  vpc_subnet_ids         = [aws_subnet.subnet_az1.id, aws_subnet.subnet_az2.id]
  vpc_security_group_ids = [aws_security_group.rds_proxy_sg.id]
  require_tls            = false
  idle_client_timeout    = 1800
  max_connections_percent = 100
  max_idle_connections_percent = 50
  debug_logging          = false
  tags = {
    Name = "aurora-rds-proxy"
  }
}

# RDS Proxy Default Target Group
resource "aws_db_proxy_default_target_group" "default" {
  db_proxy_name = aws_db_proxy.rds_proxy.name
  db_instance_identifier = aws_rds_cluster_instance.cluster_instances[0].id
  target_type = "RDS_INSTANCE"
  connection_pool_configuration {
    max_connections_percent = 100
    max_idle_connections_percent = 50
    connection_borrow_timeout = 120
    init_query = "SET time_zone = '+00:00'"
    max_db_connections = 100
    session_pinning_filters = []
  }
}

# Allow RDS Proxy to retrieve secret from Secrets Manager
resource "aws_secretsmanager_secret_policy" "rds_proxy_secret_policy" {
  secret_arn = aws_secretsmanager_secret.db_secret.arn
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
        Action = [
          "secretsmanager:GetSecretValue",
          "secretsmanager:DescribeSecret"
        ]
        Resource = aws_secretsmanager_secret.db_secret.arn
      }
    ]
  })
}

# Provider configuration
provider "aws" {
  region = "us-west-2"
}

# Required for random password
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 4.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.0"
    }
  }
}

# Include random provider
provider "random" {}
