terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 4.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # You can change to your preferred AWS region
}

resource "aws_lightsail_instance" "example" {
  name              = "my-lightsail-instance"
  availability_zone = "${data.aws_region.current.name}a"
  blueprint_id      = "amazon_linux_2" # Amazon Linux 2 OS only
  bundle_id         = "nano_2_0"       # Small instance size
  key_pair_name     = aws_lightsail_key_pair.mykey.name
}

resource "aws_lightsail_key_pair" "mykey" {
  name = "my-lightsail-key"
}

# Optional: Open ports (e.g., SSH and HTTP)
resource "aws_lightsail_instance_public_ports" "public_ports" {
  instance_name = aws_lightsail_instance.example.name

  port_info {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidrs       = ["0.0.0.0/0"]
  }

  port_info {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidrs       = ["0.0.0.0/0"]
  }
}

# Output the public IP address
output "public_ip" {
  value = aws_lightsail_instance.example.public_ip_address
}

# Get current region
data "aws_region" "current" {}
```

