resource "aws_dlm_lifecycle_policy" "glacier_policy" {
  description = "Lifecycle policy for S3 Glacier vault backups"
  execution_role_arn = aws_iam_role.dlm_role.arn
  state       = "ENABLED"

  policy_details {
    policy_type = "EVENT_BASED_POLICY"

    event_source {
      type = "MANAGED_CWE"

      parameters {
        description = "Event triggered by CloudWatch Events for Glacier backups"
        event_type  = "INSANT_SNAPSHOT"
        snapshot_tags {
          key   = "backup"
          value = "glacier-backup"
        }
      }
    }

    action {
      name = "glacier-backup-action"
      cross_region_copy {
        target = "us-east-1" # Example target region

        encryption_configuration {}

        retention_rule {
          interval           = 90
          interval_unit      = "DAYS"
          retain_rule_in_days = 90
        }
      }
    }
  }

  tags = {
    Name = "GlacierLifecyclePolicy"
  }
}

