resource "aws_glacier_vault" "example" {
  name = "example-vault"

  # Enable Vault Lock by configuring a vault lock policy
  # This is done indirectly by configuring a separate aws_glacier_vault_lock resource
}

resource "aws_glacier_vault_lock" "example" {
  vault_name      = aws_glacier_vault.example.name
  policy          = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Deny"
        Principal = "*"
        Action    = "glacier:DeleteArchive"
        Resource  = aws_glacier_vault.example.arn
        Condition = {
          NumericLessThan = {
            "glacier:ArchiveAgeInDays" = "365"
          }
        }
      }
    ]
  })
  complete_lock = false # Set to true after testing to permanently lock the policy
}

