}

response:
```hcl
resource "aws_eip" "lb_eip" {
  count = length(var.elastic_ips)

  # Associate each Elastic IP; we'll reference them by index later
  vpc      = true
  network_interface = aws_network_interface.lb_ni[count.index].id
}

resource "aws_network_interface" "lb_ni" {
  count = length(var.elastic_ips)

  subnet_id       = var.subnet_ids[count.index]
  private_ips     = [cidrhost(var.private_ip_cidr_blocks[count.index], 1)]
  security_groups = var.security_group_ids
}

resource "aws_lb" "example" {
  name               = "example-load-balancer"
  internal           = false
  load_balancer_type = "network"  # Use "application" for ALB
  subnets            = var.subnet_ids

  # Enable static IPs by assigning EIPs to the load balancer
  enable_deletion_protection = false

  # Mapping EIPs to subnets via network interfaces
  dynamic "subnet_mapping" {
    for_each = aws_network_interface.lb_ni[*].id
    content {
      subnet_id            = var.subnet_ids[subnet_mapping.key]
      allocation_id        = aws_eip.lb_eip[subnet_mapping.key].id
      private_ipv4_address = cidrhost(var.private_ip_cidr_blocks[subnet_mapping.key], 1)
    }
  }
}

variable "elastic_ips" {
  description = "List of Elastic IP allocation IDs to use for the load balancer"
  type        = list(string)
}

variable "subnet_ids" {
  description = "List of subnet IDs for the load balancer"
  type        = list(string)
}

variable "private_ip_cidr_blocks" {
  description = "List of CIDR blocks for private IP assignment in each subnet"
  type        = list(string)
}

variable "security_group_ids" {
  description = "List of security group IDs to attach to the network interfaces"
  type        = list(string)
}
```

