resource "aws_lb" "internal_load_balancer" {
  name               = "internal-lb"
  internal           = true
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]
  subnets            = aws_subnet.private[*].id

  # Specify Elastic IPs for the load balancer's subnets (if required)
  enable_deletion_protection = false

  # Map specific private IPs to subnets (requires pre-existing subnet configurations)
  dynamic "subnet_mapping" {
    for_each = var.private_ips
    content {
      subnet_id     = subnet_mapping.value.subnet_id
      private_ipv4_address = subnet_mapping.value.private_ip
    }
  }

  tags = {
    Name = "InternalLoadBalancer"
  }
}

# Example variables for private IPs and subnets
variable "private_ips" {
  description = "Map of subnet IDs to specific private IP addresses"
  type = map(object({
    subnet_id   = string
    private_ip  = string
  }))
  default = {}
}

# Security group for the load balancer (minimal inbound access)
resource "aws_security_group" "lb_sg" {
  name        = "internal-lb-sg"
  description = "Security group for internal load balancer"
  vpc_id      = var.vpc_id

  ingress {
    from_port   = 80
    to_port     = 80
    protocol    = "tcp"
    cidr_blocks = ["10.0.0.0/8"]  # Adjust to internal network range
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Example subnets (assumed to be created elsewhere or provided via variables)
variable "vpc_id" {
  description = "ID of the VPC for the internal load balancer"
  type        = string
}

