resource "aws_lb" "example" {
  name               = "example-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb_sg.id]
  subnets            = aws_subnet.public[*].id
}

resource "aws_lb_target_group" "example" {
  name     = "example-target-group"
  port     = 80
  protocol = "HTTP"
  vpc_id   = aws_vpc.example.id

  health_check {
    path                = "/"
    interval            = 30
    timeout             = 5
    healthy_threshold   = 2
    unhealthy_threshold = 2
    matcher             = "200"
  }
}

resource "aws_lb_listener" "example" {
  load_balancer_arn = aws_lb.example.arn
  port              = 443
  protocol          = "HTTPS"
  ssl_policy        = "ELBSecurityPolicy-2016-08"
  certificate_arn   = aws_acm_certificate.example.arn

  default_action {
    type = "authenticate-cognito"

    authenticate_cognito {
      user_pool_arn       = aws_cognito_user_pool.example.arn
      user_pool_client_id = aws_cognito_user_pool_client.example.id
      user_pool_domain    = aws_cognito_user_pool_domain.example.domain
    }

    forward {
      target_group_key = aws_lb_target_group.example.id
    }
  }
}

resource "aws_cognito_user_pool" "example" {
  name = "example-user-pool"
}

resource "aws_cognito_user_pool_client" "example" {
  name         = "example-client"
  user_pool_id = aws_cognito_user_pool.example.id

  generate_secret    = true
  allowed_oauth_flows = ["code"]
  allowed_oauth_scopes = ["email", "profile", "openid"]
  callback_urls      = ["https://example.com/callback"]
  logout_urls        = ["https://example.com/logout"]
  supported_identity_providers = ["COGNITO"]
}

resource "aws_cognito_user_pool_domain" "example" {
  domain          = "example-domain"
  user_pool_id    = aws_cognito_user_pool.example.id
}

resource "aws_security_group" "lb_sg" {
  name        = "example-lb-sg"
  description = "Security group for the load balancer"
  vpc_id      = aws_vpc.example.id

  ingress {
    from_port   = 443
    to_port     = 443
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
