resource "aws_db_instance" "minimal_postgresql" {
  identifier           = "minimal-postgresql-db"
  engine               = "postgres"
  engine_version       = "15.4"
  instance_class       = "db.t3.micro"
  allocated_storage    = 20
  storage_type         = "gp2"
  username             = "postgres_user"
  password             = var.db_password
  db_name              = "minimaldb"
  publicly_accessible  = false
  skip_final_snapshot  = true
  multi_az             = false
  max_allocated_storage = 20

  # Apply PostgreSQL parameters optimized for minimal memory usage
  parameter_group_name = aws_db_parameter_group.minimal_memory.id

  # Enable encryption at rest
  storage_encrypted = true

  # Enable basic backup
  backup_retention_period = 7
  backup_window           = "03:00-04:00"
  maintenance_window      = "sun:04:00-sun:05:00"
}

resource "aws_db_parameter_group" "minimal_memory" {
  name        = "minimal-postgres-param-group"
  family      = "postgres15"
  description = "PostgreSQL parameter group optimized for minimal memory usage"

  parameter {
    name  = "max_connections"
    value = "20"
  }

  parameter {
    name  = "shared_buffers"
    value = "128MB"
  }

  parameter {
    name  = "effective_cache_size"
    value = "256MB"
  }

  parameter {
    name  = "work_mem"
    value = "1MB"
  }

  parameter {
    name  = "maintenance_work_mem"
    value = "64MB"
  }

  parameter {
    name  = "checkpoint_completion_target"
    value = "0.5"
  }

  parameter {
    name  = "wal_buffers"
    value = "16MB"
  }

  parameter {
    name  = "checkpoint_segments"
    value = "8"
  }

  parameter {
    name  = "max_wal_size"
    value = "1GB"
  }

  parameter {
    name  = "min_wal_size"
    value = "80MB"
  }

  parameter {
    name  = "checkpoint_timeout"
    value = "10min"
  }

  parameter {
    name  = "random_page_cost"
    value = "2.0"
  }

  # Disable unused features
  parameter {
    name  = "logging_collector"
    value = "0"
  }

  parameter {
    name  = "fsync"
    value = "1"
  }

  parameter {
    name  = "synchronous_commit"
    value = "off"
  }
}

variable "db_password" {
  type        = string
  description = "Password for the PostgreSQL master user"
  sensitive   = true
}

