provider "aws" {
  region = "us-west-2"
}

# Create a KMS key to encrypt the database master credentials
resource "aws_kms_key" "db_credentials_key" {
  description             = "KMS key for encrypting database master credentials"
  enable_key_rotation     = true
  deletion_window_in_days = 30
}

# Create a secret in Secrets Manager for the RDS database credentials
resource "aws_secretsmanager_secret" "db_secret" {
  name       = "my-db-credentials"
  kms_key_id = aws_kms_key.db_credentials_key.arn
}

# Generate a random password for the database master user
resource "random_password" "db_password" {
  length           = 16
  special          = true
  override_special = "!@#$%&*"
}

# Store the generated credentials in the secret
resource "aws_secretsmanager_secret_version" "db_secret_version" {
  secret_id     = aws_secretsmanager_secret.db_secret.id
  secret_string = jsonencode({
    username = "dbadmin"
    password = random_password.db_password.result
  })
}

# Create the RDS instance using the credentials from Secrets Manager
resource "aws_db_instance" "default" {
  identifier               = "my-secure-database"
  allocated_storage        = 20
  storage_type             = "gp3"
  engine                   = "postgres"
  engine_version           = "14.7"
  instance_class           = "db.t3.micro"
  name                     = "mydb"
  username                 = "dbadmin"
  # Password will be sourced from Secrets Manager via IAM Authentication or application logic
  skip_final_snapshot      = true
  deletion_protection      = false
  parameter_group_name     = "default.postgres14"
  vpc_security_group_ids   = [aws_security_group.db_sg.id]
  db_subnet_group_name     = aws_db_subnet_group.db_subnet_group.name
  manage_master_user_password = true
  master_user_secret_kms_key_id = aws_kms_key.db_credentials_key.arn

  # Enable performance insights and use the KMS key
  performance_insights_enabled = true
  performance_insights_kms_key_id = aws_kms_key.db_credentials_key.arn
}

# Security group for the RDS instance
resource "aws_security_group" "db_sg" {
  name        = "db-security-group"
  description = "Allow PostgreSQL access"

  ingress {
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]  # Modify as needed for production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Subnet group for RDS (assumes you have at least two private subnets)
resource "aws_db_subnet_group" "db_subnet_group" {
  name       = "main-db-subnet-group"
  subnet_ids = ["subnet-12345678", "subnet-87654321"]  # Replace with actual subnet IDs
  tags = {
    Name = "DB Subnet Group"
  }
}

